  const [martinaData, setMartinaData] = useState(() =>
    tenant.isOeffentlich
      ? (loadStammdaten('oeffentlich', 'martina') as any)
      : {
          name: K2_STAMMDATEN_DEFAULTS.martina.name,
          category: 'malerei',
          bio: 'Martina bringt mit ihren Gemälden eine lebendige Vielfalt an Farben und Ausdruckskraft auf die Leinwand. ihre Werke spiegeln Jahre des Lernens, Experimentierens und der Leidenschaft für die Malerei wider.',
          email: K2_STAMMDATEN_DEFAULTS.martina.email,
          phone: K2_STAMMDATEN_DEFAULTS.martina.phone,
          website: K2_STAMMDATEN_DEFAULTS.martina.website || '',
          vita: ''
        }
  )
  const [georgData, setGeorgData] = useState(() =>
    tenant.isOeffentlich
      ? (loadStammdaten('oeffentlich', 'georg') as any)
      : {
          name: K2_STAMMDATEN_DEFAULTS.georg.name,
          category: 'keramik',
          bio: 'Georg verbindet in seiner Keramikarbeit technisches Können mit kreativer Gestaltung. Seine Arbeiten sind geprägt von Präzision und einer Liebe zum Detail, das Ergebnis von jahrzehntelanger Erfahrung.',
          email: K2_STAMMDATEN_DEFAULTS.georg.email,
          phone: K2_STAMMDATEN_DEFAULTS.georg.phone,
          website: K2_STAMMDATEN_DEFAULTS.georg.website || '',
          vita: ''
        }
  )
  const [galleryData, setGalleryData] = useState<any>(() =>
    tenant.isOeffentlich
      ? (loadStammdaten('oeffentlich', 'gallery') as any)
      : {
          name: K2_STAMMDATEN_DEFAULTS.gallery.name,
          subtitle: 'Kunst & Keramik',
          description: 'Gemeinsam eröffnen Martina und Georg nach über 20 Jahren kreativer Tätigkeit die K2 Galerie – ein Raum, wo Malerei und Keramik verschmelzen und Kunst zum Leben erwacht.',
          address: K2_STAMMDATEN_DEFAULTS.gallery.address,
          city: K2_STAMMDATEN_DEFAULTS.gallery.city,
          country: K2_STAMMDATEN_DEFAULTS.gallery.country,
          phone: K2_STAMMDATEN_DEFAULTS.gallery.phone,
          email: K2_STAMMDATEN_DEFAULTS.gallery.email,
          website: K2_STAMMDATEN_DEFAULTS.gallery.website,
          internetadresse: K2_STAMMDATEN_DEFAULTS.gallery.internetadresse || K2_STAMMDATEN_DEFAULTS.gallery.website,
          openingHours: K2_STAMMDATEN_DEFAULTS.gallery.openingHours,
          bankverbindung: K2_STAMMDATEN_DEFAULTS.gallery.bankverbindung,
          iban: (K2_STAMMDATEN_DEFAULTS.gallery as any).iban ?? '',
          bic: (K2_STAMMDATEN_DEFAULTS.gallery as any).bic ?? '',
          adminPassword: '',
          soldArtworksDisplayDays: 30,
          welcomeImage: '',
          virtualTourImage: '',
          galerieCardImage: '',
          internetShopNotSetUp: true
        }
  )

  // Seitengestaltung (Willkommensseite & Galerie-Vorschau) – K2 vs. ök2 getrennt
  const [pageContent, setPageContent] = useState<PageContentGalerie>(() => getPageContentGalerie(tenant.isOeffentlich ? 'oeffentlich' : tenant.isVk2 ? 'vk2' : undefined))
  const [videoUploadStatus, setVideoUploadStatus] = useState<'idle' | 'uploading' | 'done' | 'error'>('idle')
  const [videoUploadMsg, setVideoUploadMsg] = useState('')
  /** Dynamischer Mandant (?tenantId=): true bis Daten von API geladen (oder 404). */
  const [dynamicTenantLoading, setDynamicTenantLoading] = useState(!!tenant.dynamicTenantId)
  useEffect(() => {
    if (tenant.dynamicTenantId) return
    const pc = getPageContentGalerie(tenant.isOeffentlich ? 'oeffentlich' : tenant.isVk2 ? 'vk2' : undefined)
    // Wenn kein Bild im localStorage: nur bei K2 aus gallery-data.json nachladen (K2-Daten dürfen nie in VK2/ök2)
    if (!pc.welcomeImage && !tenant.isOeffentlich && !tenant.isVk2) {
      fetch(`/gallery-data.json?_=${Date.now()}`)
        .then(r => r.json())
        .then(data => {
          if (data?.gallery?.welcomeImage) {
            setPageContent(prev => ({
              ...prev,
              welcomeImage: prev.welcomeImage || data.gallery.welcomeImage,
              // Galerie-Karte und Virtueller Rundgang nicht aus gallery-data füllen – sonst erscheint immer das alte Bild
              // galerieCardImage / virtualTourImage bleiben aus localStorage (getPageContentGalerie)
            }))
          }
        })
        .catch(() => {})
    } else {
      setPageContent(pc)
    }
  }, [])

  /** Ein Standard: Video für Virtuellen Rundgang wählen – Design Seite 1 und Seite 2 nutzen dieselbe Logik. */
  const handleVirtualTourVideoFile = useCallback(async (f: File) => {
    if (f.size > 100 * 1024 * 1024) {
      setVideoUploadMsg('Video ist zu groß (max. 100 MB).')
      setVideoUploadStatus('error')
      return
    }
    setVideoUploadStatus('uploading')
    setVideoUploadMsg('Video wird vorbereitet…')
    try {
      const durationSec = await getVideoDurationSec(f)
      if (durationSec > MAX_VIDEO_DURATION_SEC) {
        setVideoUploadMsg(`Video darf max. 2 Minuten lang sein (${Math.round(durationSec)} s) – für schnelles Laden.`)
        setVideoUploadStatus('error')
        return
      }
    } catch {
      setVideoUploadMsg('Länge konnte nicht gelesen werden.')
      setVideoUploadStatus('error')
      return
    }
    try {
      const localUrl = URL.createObjectURL(f)
      const tenantId = tenant.isOeffentlich ? 'oeffentlich' : tenant.isVk2 ? 'vk2' : undefined
      const nextLocal = { ...pageContent, virtualTourVideo: localUrl, virtualTourVideoSizeBytes: f.size }
      setPageContent(nextLocal)
      setPageContentGalerie(nextLocal, tenantId)
      // Upload für dauerhafte URL (blob ist nur session-gebunden → Video verschwindet sonst nach kurzer Zeit)
      setVideoUploadStatus('uploading')
      setVideoUploadMsg(tenant.isOeffentlich ? 'Video wird gespeichert…' : 'Video wird hochgeladen… Bitte warten.')
      try {
        const { uploadVideoToGitHub } = await import('../src/utils/githubImageUpload')
        const subfolder = tenant.isOeffentlich ? 'oeffentlich' : 'k2'
        const url = await uploadVideoToGitHub(f, 'virtual-tour.mp4', (msg) => setVideoUploadMsg(msg), subfolder)
        const nextVercel = { ...nextLocal, virtualTourVideo: url }
        setPageContent(nextVercel)
        setPageContentGalerie(nextVercel, tenantId)
        if (!tenant.isOeffentlich) localStorage.removeItem('k2-last-publish-signature')
        setVideoUploadStatus('done')
        setVideoUploadMsg(tenant.isOeffentlich ? '✅ Video gespeichert – bleibt in der Galerie sichtbar.' : '✅ Video hochgeladen – in ca. 2 Min. überall sichtbar.')
      } catch {
        setVideoUploadStatus('error')
        setVideoUploadMsg('Upload fehlgeschlagen – Video nur auf diesem Gerät sichtbar.')
      }
    } catch {
      setVideoUploadStatus('error')
      setVideoUploadMsg('Fehler beim Laden des Videos.')
    }
  }, [pageContent, tenant])

  // Design-Vorschau = immer aktuelle gespeicherte Seite anzeigen (keine alten Daten)
  // Beim Wechsel in den Design-Tab ODER Mandanten (K2/ök2/VK2): Seitentexte, Seitengestaltung und Design aus dem richtigen Key nachladen – sonst landet K2-Bild in VK2 beim Speichern
  const designTenantKey = tenant.isOeffentlich ? 'oeffentlich' : tenant.isVk2 ? 'vk2' : 'k2'
  useEffect(() => {
    if (activeTab !== 'design') return
    const designTenant = tenant.isOeffentlich ? 'oeffentlich' : tenant.isVk2 ? 'vk2' : undefined
    setPageTextsState(getPageTexts(designTenant))
    setPageContent(getPageContentGalerie(designTenant))
    try {
      const key = getDesignStorageKey()
      const stored = localStorage.getItem(key)
      if (stored && stored.length > 0 && stored.length < 50000) {
        const parsed = JSON.parse(stored)
        if (parsed && typeof parsed === 'object' && (parsed.accentColor || parsed.backgroundColor1)) {
          const defaults = tenant.isOeffentlich ? OEF_DESIGN_DEFAULT : K2_ORANGE_DESIGN
          if (!tenant.isOeffentlich && isOldBlueDesign(parsed)) {
            setDesignSettings(K2_ORANGE_DESIGN)
          } else {
            setDesignSettings({
              accentColor: parsed.accentColor ?? (defaults as Record<string, string>).accentColor,
              backgroundColor1: parsed.backgroundColor1 ?? (defaults as Record<string, string>).backgroundColor1,
              backgroundColor2: parsed.backgroundColor2 ?? (defaults as Record<string, string>).backgroundColor2,
              backgroundColor3: parsed.backgroundColor3 ?? (defaults as Record<string, string>).backgroundColor3,
              textColor: parsed.textColor ?? (defaults as Record<string, string>).textColor,
              mutedColor: parsed.mutedColor ?? (defaults as Record<string, string>).mutedColor,
              cardBg1: parsed.cardBg1 ?? (defaults as Record<string, string>).cardBg1,
              cardBg2: parsed.cardBg2 ?? (defaults as Record<string, string>).cardBg2
            })
          }
        }
      }
    } catch (_) {}
  }, [activeTab, designTenantKey])

  // URL-Parameter context (oeffentlich / vk2) in sessionStorage übernehmen
  // WICHTIG: Wenn kein context-Parameter → K2-Admin → sessionStorage löschen (verhindert "hängenbleiben" im ök2-Kontext)
  useEffect(() => {
    try {
      const params = new URLSearchParams(window.location.search)
      const ctx = params.get('context')
      if (ctx === 'oeffentlich') sessionStorage.setItem(ADMIN_CONTEXT_KEY, 'oeffentlich')
      else if (ctx === 'vk2') sessionStorage.setItem(ADMIN_CONTEXT_KEY, 'vk2')
      else sessionStorage.removeItem(ADMIN_CONTEXT_KEY) // Kein context = K2, alten Kontext löschen
    } catch (_) {}
  }, [])

  // Dynamischer Mandant (?tenantId=): Daten von API laden, in State übernehmen – kein localStorage
  useEffect(() => {
    const dynId = tenant.dynamicTenantId
    if (!dynId) return
    let isMounted = true
    const url = `${CENTRAL_GALLERY_DATA_URL}?v=${Date.now()}&tenantId=${encodeURIComponent(dynId)}`
    apiGet(url, { retryOnce: false }).then((result) => {
      if (!isMounted) return
      setDynamicTenantLoading(false)
      if (!result.success) {
        if (result.error?.includes('404') || result.error?.toLowerCase().includes('noch keine')) {
          setAllArtworksSafe([])
          setEvents([])
          setDocuments([])
          setMartinaData(K2_STAMMDATEN_DEFAULTS.martina as any)
          setGeorgData(K2_STAMMDATEN_DEFAULTS.georg as any)
          setGalleryData({ ...K2_STAMMDATEN_DEFAULTS.gallery, adminPassword: '', soldArtworksDisplayDays: 30, welcomeImage: '', virtualTourImage: '', galerieCardImage: '', internetShopNotSetUp: true })
          setPageContent({ welcomeImage: '', galerieCardImage: '', virtualTourImage: '', virtualTourVideo: '', virtualTourVideoSizeBytes: 0 })
          setDesignSettings(K2_ORANGE_DESIGN)
          setPageTextsState(defaultPageTexts)
        }
        return
      }
      const data = (result.data || {}) as Record<string, unknown>
      const artworks = Array.isArray(data.artworks) ? data.artworks : []
      const fromStorage = loadArtworks(tenant)
      const withRefs = preserveStorageImageRefs(artworks, fromStorage, (x: any) => String(x?.number ?? x?.id ?? '').trim())
      setAllArtworksSafe(withRefs)
      if (!tenant.isOeffentlich && !tenant.isVk2) {
        const localDesignRaw = typeof localStorage !== 'undefined' ? localStorage.getItem('k2-design-settings') : null
        const localDesign = localDesignRaw ? (() => { try { return JSON.parse(localDesignRaw) } catch { return null } })() : null
        const localPageTextsRaw = typeof localStorage !== 'undefined' ? localStorage.getItem('k2-page-texts') : null
        const localPageTexts = localPageTextsRaw ? (() => { try { return JSON.parse(localPageTextsRaw) } catch { return null } })() : null
        const toApply = applyServerPayloadK2(data, {
          events: loadEventsFromStorage('k2'),
          documents: loadDocumentsFromStorage('k2'),
          designSettings: localDesign,
          pageTexts: localPageTexts
        })
        setEvents(toApply.events != null ? toApply.events : loadEventsFromStorage('k2'))
        setDocuments(toApply.documents != null ? toApply.documents : loadDocumentsFromStorage('k2'))
        if (toApply.designSettings != null) setDesignSettings({ ...K2_ORANGE_DESIGN, ...toApply.designSettings } as any)
        else if (localDesign) setDesignSettings({ ...K2_ORANGE_DESIGN, ...localDesign } as any)
        if (toApply.pageTexts != null) setPageTextsState({ ...defaultPageTexts, ...toApply.pageTexts } as any)
        else if (localPageTexts) setPageTextsState({ ...defaultPageTexts, ...localPageTexts } as any)
      } else {
        setEvents(Array.isArray(data.events) ? data.events : [])
        setDocuments(Array.isArray(data.documents) ? data.documents : [])
        if (data.designSettings && typeof data.designSettings === 'object') setDesignSettings({ ...K2_ORANGE_DESIGN, ...data.designSettings } as any)
        if (data.pageTexts && typeof data.pageTexts === 'object') setPageTextsState({ ...defaultPageTexts, ...data.pageTexts } as any)
      }
      if (data.martina && typeof data.martina === 'object') setMartinaData({ ...K2_STAMMDATEN_DEFAULTS.martina, ...data.martina } as any)
      else setMartinaData(K2_STAMMDATEN_DEFAULTS.martina as any)
      if (data.georg && typeof data.georg === 'object') setGeorgData({ ...K2_STAMMDATEN_DEFAULTS.georg, ...data.georg } as any)
      else setGeorgData(K2_STAMMDATEN_DEFAULTS.georg as any)
      if (data.gallery && typeof data.gallery === 'object') setGalleryData({ ...K2_STAMMDATEN_DEFAULTS.gallery, ...data.gallery })
      else setGalleryData({ ...K2_STAMMDATEN_DEFAULTS.gallery, adminPassword: '', soldArtworksDisplayDays: 30, welcomeImage: '', virtualTourImage: '', galerieCardImage: '', internetShopNotSetUp: true })
      const pc = data.pageContentGalerie ?? data.pageContent
      if (pc != null) {
        const parsed = typeof pc === 'string' ? (() => { try { return JSON.parse(pc) } catch { return {} } })() : pc
        if (typeof parsed === 'object') setPageContent({ welcomeImage: '', galerieCardImage: '', virtualTourImage: '', virtualTourVideo: '', virtualTourVideoSizeBytes: 0, ...parsed })
      }
    }).catch(() => {
      if (isMounted) setDynamicTenantLoading(false)
    })
    return () => { isMounted = false }
  }, [tenant.dynamicTenantId])

  // ök2: Lager-Tab nicht verfügbar. VK2: Sicherheit und Lager nicht – auf Stammdaten wechseln
  useEffect(() => {
    if (tenant.isVk2 && settingsSubTab === 'sicherheit') setSettingsSubTab('stammdaten')
  }, [settingsSubTab])

  // Einstellungen: Beim Klick auf eine Karte (Meine Daten, Drucker, …) sofort den geöffneten Bereich in den sichtbaren Bereich scrollen (v. a. Handy)
  useEffect(() => {
    if (activeTab !== 'einstellungen') return
    const el = settingsContentRef.current
    if (!el) return
    const t = setTimeout(() => {
      if (el.isConnected) el.scrollIntoView({ behavior: 'smooth', block: 'start' })
    }, 50)
    return () => clearTimeout(t)
  }, [activeTab, settingsSubTab])

  // Besucher-Ticker: Zahl für aktuellen Kontext laden (K2 / ök2 / VK2 Summe)
  useEffect(() => {
    let isMounted = true
    const origin = typeof window !== 'undefined' ? window.location.origin : ''
    if (tenant.isVk2) {
      Promise.all([
        fetch(`${origin}/api/visit?tenant=vk2-members`).then((r) => r.json()).then((d) => d.count ?? 0),
        fetch(`${origin}/api/visit?tenant=vk2-external`).then((r) => r.json()).then((d) => d.count ?? 0),
      ]).then(([m, e]) => { if (isMounted) setBesucherCount(m + e) }).catch(() => { if (isMounted) setBesucherCount(null) })
    } else if (tenant.isOeffentlich) {
      fetch(`${origin}/api/visit?tenant=oeffentlich`).then((r) => r.json()).then((d) => { if (isMounted) setBesucherCount(d.count ?? 0) }).catch(() => { if (isMounted) setBesucherCount(null) })
    } else {
      fetch(`${origin}/api/visit?tenant=k2`).then((r) => r.json()).then((d) => { if (isMounted) setBesucherCount(d.count ?? 0) }).catch(() => { if (isMounted) setBesucherCount(null) })
    }
    return () => { isMounted = false }
  }, [tenant.isOeffentlich, tenant.isVk2])

  // ök2: Verkaufte-Werke-Anzeige (Tage) aus k2-oeffentlich-galerie-settings laden
  useEffect(() => {
    if (!tenant.isOeffentlich) return
    try {
      const raw = localStorage.getItem('k2-oeffentlich-galerie-settings')
      if (raw) {
        const o = JSON.parse(raw)
        if (typeof o.soldArtworksDisplayDays === 'number') setSoldArtworksDisplayDaysOek2(o.soldArtworksDisplayDays)
      }
    } catch (_) {}
  }, [])

  // ök2: Beim Wechsel in Kontext „Öffentliche Galerie“ Galerie-Stammdaten laden (inkl. focusDirections für Filter/Neues Werk)
  useEffect(() => {
    if (!tenant.isOeffentlich) return
    try {
      const data = loadStammdaten('oeffentlich', 'gallery') as Record<string, unknown> | null
      const g = (K2_STAMMDATEN_DEFAULTS.gallery as any) || {}
      const rawFd = data && typeof data === 'object' && Array.isArray((data as any).focusDirections) ? (data as any).focusDirections : []
      const fdOne = rawFd.length > 0 ? [rawFd[0]] : [DEFAULT_OEK2_FOCUS_DIRECTION_ID]
      const merged = data && typeof data === 'object'
        ? { ...g, ...data, focusDirections: fdOne }
        : { ...g, focusDirections: [DEFAULT_OEK2_FOCUS_DIRECTION_ID] }
      setGalleryData(merged)
    } catch (_) {}
  }, [tenant.isOeffentlich])

  // ök2: Beim Wechsel zum Tab „Werke“ focusDirections aus localStorage nachziehen, damit Typ/Kategorie zur gespeicherten Richtung passen
  useEffect(() => {
    if (activeTab !== 'werke' || !tenant.isOeffentlich) return
    try {
      const data = loadStammdaten('oeffentlich', 'gallery') as Record<string, unknown> | null
      if (data && typeof data === 'object' && Array.isArray((data as any).focusDirections)) {
        const fd = (data as any).focusDirections
        const one = fd.length > 0 ? [fd[0]] : [DEFAULT_OEK2_FOCUS_DIRECTION_ID]
        setGalleryData((prev: any) => {
          if (prev && JSON.stringify(prev.focusDirections) === JSON.stringify(one)) return prev
          return { ...(prev || {}), ...data, focusDirections: one }
        })
      }
    } catch (_) {}
  }, [activeTab, tenant.isOeffentlich])

  // K2: Verkaufte-Werke-Anzeige (Tage) aus k2-stammdaten-galerie laden (bei Werke-Tab) – isMounted gegen setState nach Unmount (HMR/Code 5)
  useEffect(() => {
    if (tenant.isOeffentlich || tenant.isVk2) return
    let isMounted = true
    try {
      const g = loadStammdaten('k2', 'gallery') as { soldArtworksDisplayDays?: number }
      if (isMounted && g && typeof g.soldArtworksDisplayDays === 'number') setSoldArtworksDisplayDaysK2(g.soldArtworksDisplayDays)
    } catch (_) {}
    return () => { isMounted = false }
  }, [activeTab, tenant.isOeffentlich, tenant.isVk2])

  // Stammdaten aus localStorage laden – bei ök2-Kontext aus k2-oeffentlich-stammdaten-*; bei VK2 aus k2-vk2-stammdaten
  useEffect(() => {
    if (tenant.dynamicTenantId) return
    if (tenant.isOeffentlich) return
    if (tenant.isVk2) return // VK2 lädt in separatem Effect
    let isMounted = true
    
    const timeoutId = setTimeout(() => {
      if (!isMounted) return
      
      try {
        // Einmalig: Wenn K2-Stammdaten leer sind, aber der Kunde in der Muster-Galerie schon etwas eingegeben hat → übernehmen (Schicht: stammdatenStorage)
        const k2MartinaObj = loadStammdaten('k2', 'martina')
        const oefMartinaObj = loadStammdaten('oeffentlich', 'martina')
        const k2MartinaEmpty = !k2MartinaObj || (typeof k2MartinaObj === 'object' && (!k2MartinaObj.name || !k2MartinaObj.email))
        if (k2MartinaEmpty && oefMartinaObj && typeof oefMartinaObj === 'object' && (oefMartinaObj.name || oefMartinaObj.email)) {
          try {
            persistStammdaten('k2', 'martina', oefMartinaObj)
            persistStammdaten('k2', 'georg', loadStammdaten('oeffentlich', 'georg'))
            persistStammdaten('k2', 'gallery', loadStammdaten('oeffentlich', 'gallery'))
          } catch (_) {}
        }
        
        const storedMartina = loadStammdaten('k2', 'martina') as Record<string, unknown>
        const d = K2_STAMMDATEN_DEFAULTS.martina
        let mergedMartina: any
        if (storedMartina && typeof storedMartina === 'object' && JSON.stringify(storedMartina).length < 100000) {
          const parsed = storedMartina
          mergedMartina = {
            ...parsed,
            name: (parsed.name && String(parsed.name).trim()) ? parsed.name : d.name,
            email: (parsed.email && String(parsed.email).trim()) ? parsed.email : d.email,
            phone: (parsed.phone && String(parsed.phone).trim()) ? parsed.phone : d.phone,
            website: (parsed.website && String(parsed.website).trim()) ? parsed.website : (d.website || ''),
            address: (parsed.address != null && String(parsed.address).trim()) ? parsed.address : (d.address ?? ''),
            city: (parsed.city != null && String(parsed.city).trim()) ? parsed.city : (d.city ?? ''),
            country: (parsed.country != null && String(parsed.country).trim()) ? parsed.country : (d.country ?? '')
          }
          if (!mergedMartina.vita || typeof mergedMartina.vita !== 'string' || !mergedMartina.vita.trim()) {
            mergedMartina.vita = MUSTER_VITA_MARTINA
          }
        } else {
          mergedMartina = { name: d.name, email: d.email, phone: d.phone, website: d.website || '', address: (d as any).address ?? '', city: (d as any).city ?? '', country: (d as any).country ?? '', category: 'malerei', bio: '', vita: MUSTER_VITA_MARTINA }
        }
        if (isMounted) setMartinaData(mergedMartina)
        // Nur Kontaktfelder/Adresse reparieren – niemals komplette Stammdaten überschreiben (sonst gehen Bio, Bilder verloren). Schicht: saveStammdaten.
        if (storedMartina && typeof storedMartina === 'object' && JSON.stringify(storedMartina).length < 100000) {
          try {
            const toWrite = { ...storedMartina, name: mergedMartina.name, email: mergedMartina.email, phone: mergedMartina.phone, website: mergedMartina.website, address: mergedMartina.address, city: mergedMartina.city, country: mergedMartina.country }
            persistStammdaten('k2', 'martina', toWrite)
          } catch (_) {}
        }
      } catch (error) {
        console.error('Fehler beim Laden von Martina-Daten:', error)
      }
      
      if (!isMounted) return
      
      try {
        const storedGeorg = loadStammdaten('k2', 'georg') as Record<string, unknown>
        const d = K2_STAMMDATEN_DEFAULTS.georg
        let mergedGeorg: any
        if (storedGeorg && typeof storedGeorg === 'object' && JSON.stringify(storedGeorg).length < 100000) {
          const parsed = storedGeorg
          mergedGeorg = {
            ...parsed,
            name: (parsed.name && String(parsed.name).trim()) ? parsed.name : d.name,
            email: (parsed.email && String(parsed.email).trim()) ? parsed.email : d.email,
            phone: (parsed.phone && String(parsed.phone).trim()) ? parsed.phone : d.phone,
            website: (parsed.website && String(parsed.website).trim()) ? parsed.website : (d.website || ''),
            address: (parsed.address != null && String(parsed.address).trim()) ? parsed.address : (d.address ?? ''),
            city: (parsed.city != null && String(parsed.city).trim()) ? parsed.city : (d.city ?? ''),
            country: (parsed.country != null && String(parsed.country).trim()) ? parsed.country : (d.country ?? '')
          }
          if (!mergedGeorg.vita || typeof mergedGeorg.vita !== 'string' || !mergedGeorg.vita.trim()) {
            mergedGeorg.vita = MUSTER_VITA_GEORG
          }
        } else {
          mergedGeorg = { name: d.name, email: d.email, phone: d.phone, website: d.website || '', address: (d as any).address ?? '', city: (d as any).city ?? '', country: (d as any).country ?? '', category: 'keramik', bio: '', vita: MUSTER_VITA_GEORG }
        }
        if (isMounted) setGeorgData(mergedGeorg)
        if (storedGeorg && typeof storedGeorg === 'object' && JSON.stringify(storedGeorg).length < 100000) {
          try {
            const toWrite = { ...storedGeorg, name: mergedGeorg.name, email: mergedGeorg.email, phone: mergedGeorg.phone, website: mergedGeorg.website, address: mergedGeorg.address, city: mergedGeorg.city, country: mergedGeorg.country }
            persistStammdaten('k2', 'georg', toWrite)
          } catch (_) {}
        }
      } catch (error) {
        console.error('Fehler beim Laden von Georg-Daten:', error)
      }
      
      if (!isMounted) return
      
      try {
        const data = loadStammdaten('k2', 'gallery') as Record<string, unknown> | null
        const g = K2_STAMMDATEN_DEFAULTS.gallery
        let mergedGallery: any
        if (data && typeof data === 'object') {
          // Bestehende Daten behalten (Adresse, welcomeImage, virtualTourImage, soldArtworksDisplayDays, etc.) – nur leere Kontaktfelder aus Defaults füllen
          mergedGallery = {
            ...data,
            name: (data.name && String(data.name).trim()) ? data.name : g.name,
            phone: (data.phone && String(data.phone).trim()) ? data.phone : g.phone,
            email: (data.email && String(data.email).trim()) ? data.email : g.email,
            address: (data.address != null && String(data.address).trim()) ? data.address : (g.address || data.address),
            city: (data.city != null && String(data.city).trim()) ? data.city : (g.city || data.city),
            country: (data.country != null && String(data.country).trim()) ? data.country : (g.country || data.country),
            website: (data.website != null && String(data.website).trim()) ? data.website : (g.website || data.website || ''),
            internetadresse: (data.internetadresse != null && String(data.internetadresse).trim()) ? data.internetadresse : (data.website || g.internetadresse || ''),
            openingHours: (data.openingHours != null && String(data.openingHours).trim()) ? data.openingHours : (g.openingHours || data.openingHours || ''),
            bankverbindung: (data.bankverbindung != null && String(data.bankverbindung).trim()) ? data.bankverbindung : (g.bankverbindung || data.bankverbindung || ''),
            iban: (data.iban != null && String(data.iban).trim()) ? data.iban : ((g as any).iban ?? (data as any).iban ?? ''),
            bic: (data.bic != null && String(data.bic).trim()) ? data.bic : ((g as any).bic ?? (data as any).bic ?? ''),
            firmenname: (data.firmenname != null && String(data.firmenname).trim()) ? data.firmenname : ((g as any).firmenname ?? (data as any).firmenname ?? ''),
            ustIdNr: (data.ustIdNr != null && String(data.ustIdNr).trim()) ? data.ustIdNr : ((g as any).ustIdNr ?? (data as any).ustIdNr ?? ''),
            rechnungAddress: (data.rechnungAddress != null && String(data.rechnungAddress).trim()) ? data.rechnungAddress : ((g as any).rechnungAddress ?? (data as any).rechnungAddress ?? ''),
            rechnungCity: (data.rechnungCity != null && String(data.rechnungCity).trim()) ? data.rechnungCity : ((g as any).rechnungCity ?? (data as any).rechnungCity ?? ''),
            rechnungCountry: (data.rechnungCountry != null && String(data.rechnungCountry).trim()) ? data.rechnungCountry : ((g as any).rechnungCountry ?? (data as any).rechnungCountry ?? ''),
            soldArtworksDisplayDays: typeof data.soldArtworksDisplayDays === 'number' ? data.soldArtworksDisplayDays : 30,
            focusDirections: Array.isArray((data as any).focusDirections) ? (data as any).focusDirections : []
          }
        } else {
          mergedGallery = {
            name: g.name,
            address: g.address,
            city: g.city,
            country: g.country,
            phone: g.phone,
            email: g.email,
            website: g.website || '',
            internetadresse: g.internetadresse || '',
            openingHours: g.openingHours || '',
            bankverbindung: g.bankverbindung || '',
            iban: (g as any).iban ?? '',
            bic: (g as any).bic ?? '',
            firmenname: (g as any).firmenname ?? '',
            ustIdNr: (g as any).ustIdNr ?? '',
            rechnungAddress: (g as any).rechnungAddress ?? '',
            rechnungCity: (g as any).rechnungCity ?? '',
            rechnungCountry: (g as any).rechnungCountry ?? '',
            adminPassword: '',
            soldArtworksDisplayDays: 30,
            welcomeImage: '',
            virtualTourImage: '',
            galerieCardImage: '',
            internetShopNotSetUp: true,
            focusDirections: (() => { const fd = Array.isArray((g as any).focusDirections) ? (g as any).focusDirections : []; return fd.length > 0 ? [fd[0]] : []; })()
          }
        }
        if (isMounted) {
          setGalleryData(mergedGallery)
          // Ausstellungs-Galerie – Adresse ist immer sichtbar, kein Toggle nötig.
        }
        // Nur Kontakt/Name reparieren – niemals welcomeImage, virtualTourImage, Adresse etc. überschreiben. Schicht: saveStammdaten.
        if (data && typeof data === 'object') {
          try {
            const toWrite = {
              ...data,
              name: mergedGallery.name,
              phone: mergedGallery.phone,
              email: mergedGallery.email,
              address: mergedGallery.address,
              city: mergedGallery.city,
              country: mergedGallery.country,
              website: mergedGallery.website,
              internetadresse: mergedGallery.internetadresse,
              openingHours: mergedGallery.openingHours,
              bankverbindung: mergedGallery.bankverbindung,
              iban: (mergedGallery as any).iban ?? '',
              bic: (mergedGallery as any).bic ?? '',
              firmenname: mergedGallery.firmenname ?? '',
              ustIdNr: mergedGallery.ustIdNr ?? '',
              rechnungAddress: mergedGallery.rechnungAddress ?? '',
              rechnungCity: mergedGallery.rechnungCity ?? '',
              rechnungCountry: mergedGallery.rechnungCountry ?? '',
              focusDirections: Array.isArray((mergedGallery as any).focusDirections) ? (mergedGallery as any).focusDirections : []
            }
            persistStammdaten('k2', 'gallery', toWrite)
          } catch (_) {}
        }
      } catch (error) {
        console.error('Fehler beim Laden der Galerie-Daten:', error)
        if (isMounted) {
          const fallback = { ...K2_STAMMDATEN_DEFAULTS.gallery, adminPassword: '', soldArtworksDisplayDays: 30, welcomeImage: '', virtualTourImage: '', galerieCardImage: '', internetShopNotSetUp: true }
          setGalleryData(fallback)
        }
      }
    }, 1500) // Starke Verzögerung (Crash-Schutz: kein schweres Parsen direkt nach Reopen)
    
    return () => {
      isMounted = false
      clearTimeout(timeoutId)
    }
  }, [])

  // VK2-Stammdaten aus localStorage laden (nur bei VK2-Kontext)
  useEffect(() => {
    if (!tenant.isVk2) return
    let isMounted = true
    const t = setTimeout(() => {
      if (!isMounted) return
      try {
        const parsed = loadVk2Stammdaten() as Partial<Vk2Stammdaten> | null
        if (parsed && typeof parsed === 'object' && JSON.stringify(parsed).length < 500000) {
          const parsedMitglieder: Vk2Mitglied[] = Array.isArray(parsed.mitglieder) ? parsed.mitglieder.map((m: any) => typeof m === 'string' ? { name: m, oeffentlichSichtbar: true } : { name: m?.name ?? '', email: m?.email, lizenz: m?.lizenz, typ: m?.typ, mitgliedFotoUrl: m?.mitgliedFotoUrl, imageUrl: m?.imageUrl, phone: m?.phone, website: m?.website, seit: m?.seit, strasse: m?.strasse, plz: m?.plz, ort: m?.ort, land: m?.land, geburtsdatum: m?.geburtsdatum, eintrittsdatum: m?.eintrittsdatum ?? m?.seit, oeffentlichSichtbar: m?.oeffentlichSichtbar !== false, bankKontoinhaber: m?.bankKontoinhaber, bankIban: m?.bankIban, bankBic: m?.bankBic, bankName: m?.bankName }) : []
          const merged: Vk2Stammdaten = {
            verein: { ...VK2_STAMMDATEN_DEFAULTS.verein, ...parsed.verein },
            vorstand: { ...VK2_STAMMDATEN_DEFAULTS.vorstand, ...parsed.vorstand },
            vize: { ...VK2_STAMMDATEN_DEFAULTS.vize, ...parsed.vize },
            kassier: { ...VK2_STAMMDATEN_DEFAULTS.kassier, ...parsed.kassier },
            schriftfuehrer: { ...VK2_STAMMDATEN_DEFAULTS.schriftfuehrer, ...parsed.schriftfuehrer },
            beisitzer: parsed.beisitzer ? { ...VK2_STAMMDATEN_DEFAULTS.beisitzer!, ...parsed.beisitzer } : undefined,
            // Wenn keine Mitglieder gespeichert: Muster-Mitglieder als Fallback
            mitglieder: parsedMitglieder.length > 0 ? parsedMitglieder : USER_LISTE_FUER_MITGLIEDER,
            mitgliederNichtRegistriert: Array.isArray(parsed.mitgliederNichtRegistriert) ? parsed.mitgliederNichtRegistriert : [],
          }
          setVk2Stammdaten(merged)
        } else {
          // Kein gespeicherter Stand → Defaults + Muster-Mitglieder verwenden
          setVk2Stammdaten({ ...VK2_STAMMDATEN_DEFAULTS, mitglieder: USER_LISTE_FUER_MITGLIEDER })
        }
      } catch (_) {
        setVk2Stammdaten({ ...VK2_STAMMDATEN_DEFAULTS, mitglieder: USER_LISTE_FUER_MITGLIEDER })
      }
    }, 300)
    return () => { isMounted = false; clearTimeout(t) }
  }, [])

  // Registrierungs-Config (Lizenztyp, Vereinsmitglied, Empfehlung) aus localStorage laden
  useEffect(() => {
    let isMounted = true
    const t = setTimeout(() => {
      if (!isMounted) return
      try {
        const key = tenant.isVk2 ? KEY_VK2_REGISTRIERUNG : tenant.isOeffentlich ? KEY_OEF_REGISTRIERUNG : KEY_REGISTRIERUNG
        const raw = localStorage.getItem(key)
        if (raw && raw.length < 5000) {
          const parsed = JSON.parse(raw) as Partial<RegistrierungConfig>
          const migrated = { ...REGISTRIERUNG_CONFIG_DEFAULTS, ...parsed }
          if ((parsed as { lizenztyp?: string }).lizenztyp === 'vollversion') migrated.lizenztyp = 'pro'
          setRegistrierungConfig(migrated)
        }
      } catch (_) {}
    }, 200)
    return () => { isMounted = false; clearTimeout(t) }
  }, [])

  // VK2: Beim Öffnen des Mitglieder-Modals Vereinskatalog-Werke laden (einfaches Mitglied)
  useEffect(() => {
    if (!showAddModal || !tenant.isVk2) return
    if (editingMemberIndex === null) {
      setMemberVereinskatalogWerke([])
      setEditingVk2WerkIndex(null)
      setVk2WerkForm({ title: '', description: '', technik: '', imageUrl: '', dimensions: '', year: '' })
      return
    }
    const m = vk2Stammdaten.mitglieder?.[editingMemberIndex]
    if (!m?.name?.trim()) return
    const key = getVk2MemberArtworksKey(m.name)
    try {
      const raw = localStorage.getItem(key)
      const list = raw ? JSON.parse(raw) : []
      setMemberVereinskatalogWerke(Array.isArray(list) ? list : [])
    } catch {
      setMemberVereinskatalogWerke([])
    }
    setEditingVk2WerkIndex(null)
    setVk2WerkForm({ title: '', description: '', technik: '', imageUrl: '', dimensions: '', year: '' })
  }, [showAddModal, tenant.isVk2, editingMemberIndex])

  const saveRegistrierungConfig = () => {
    let cfg = { ...registrierungConfig }
    const praefix = getLizenznummerPraefix(cfg)
    const match = cfg.lizenznummer?.match(/^(B|P|VB|VP|KF)-(\d{4})-(\d{4})$/)
    const needsNew = !match || match[1] !== praefix
    // Lizenznummer beim ersten Speichern oder bei Präfix-Änderung vom K2-System vergeben
    if (needsNew) {
      cfg = { ...cfg, lizenznummer: `${praefix}-${new Date().getFullYear()}-${Math.floor(1000 + Math.random() * 9000)}` }
      setRegistrierungConfig(cfg)
    }
    const key = tenant.isVk2 ? KEY_VK2_REGISTRIERUNG : tenant.isOeffentlich ? KEY_OEF_REGISTRIERUNG : KEY_REGISTRIERUNG
    localStorage.setItem(key, JSON.stringify(cfg))
  }

  /** Speichert alle aktuellen Admin-Daten in localStorage (K2/ök2/VK2-Key), damit „Seiten prüfen“ die neuesten Änderungen anzeigt. Design wird hier nicht mitgeschrieben – nur über „Speichern“ im Design-Tab. Sportwagenmodus: ImageStore. */
  const saveAllForVorschau = () => {
    const run = async () => {
      try {
        if (tenant.isVk2) {
          saveVk2Stammdaten(vk2Stammdaten)
        } else if (!tenant.isOeffentlich) {
          if (JSON.stringify(martinaData).length < 100000) persistStammdaten('k2', 'martina', martinaData)
          if (JSON.stringify(georgData).length < 100000) persistStammdaten('k2', 'georg', georgData)
          if (JSON.stringify(galleryData).length < 5000000) persistStammdaten('k2', 'gallery', galleryData)
        }
        if (!tenant.isVk2) {
          await saveArtworksByKeyWithImageStore(tenant.getArtworksKey()!, allArtworks, { filterK2Only: tenant.tenantId === 'k2', allowReduce: true })
        }
        localStorage.setItem(tenant.getEventsKey(), JSON.stringify(events))
        saveDocumentsToStorage(tenant.tenantId, documents)
        setPageTexts(pageTexts, tenant.isOeffentlich ? 'oeffentlich' : tenant.isVk2 ? 'vk2' : undefined)
        setPageContentGalerie(pageContent, tenant.isOeffentlich ? 'oeffentlich' : tenant.isVk2 ? 'vk2' : undefined)
      } catch (e) {
        console.warn('Vorschau-Speichern:', e)
      }
    }
    void run()
  }

  /** Pilot/ök2: Musterdaten auf einen Klick leeren – eigene Eintragung ohne umständliches Rauslöschen. */
  const clearStammdatenMuster = () => {
    if (!tenant.isOeffentlich) return
    if (!confirm('Alle Musterdaten in Person und Galerie leeren? Du kannst danach deine eigenen Daten eintragen.')) return
    const emptyPerson1 = { name: '', email: '', phone: '', website: '', category: 'malerei' as const, bio: '', vita: '' }
    const emptyPerson2 = { name: '', email: '', phone: '', website: '', category: 'keramik' as const, bio: '', vita: '' }
    const emptyGallery = {
      name: '', subtitle: '', description: '', address: '', city: '', country: '', phone: '', email: '', website: '', internetadresse: '', openingHours: '', bankverbindung: '', iban: '', bic: '', firmenname: '', ustIdNr: '', rechnungAddress: '', rechnungCity: '', rechnungCountry: '', adminPassword: '',
      soldArtworksDisplayDays: 30, welcomeImage: '', virtualTourImage: '', galerieCardImage: '', internetShopNotSetUp: true, focusDirections: [DEFAULT_OEK2_FOCUS_DIRECTION_ID] as string[], story: ''
    }
    setMartinaData(emptyPerson1)
    setGeorgData(emptyPerson2)
    setGalleryData(emptyGallery)
    try {
      persistStammdaten('oeffentlich', 'martina', emptyPerson1, { merge: false })
      persistStammdaten('oeffentlich', 'georg', emptyPerson2, { merge: false })
      persistStammdaten('oeffentlich', 'gallery', emptyGallery, { merge: false })
    } catch (e) {
      console.warn('Musterdaten leeren (persist):', e)
    }
    setVitaMartinaOpen(false)
    alert('✅ Musterdaten entfernt. Trage jetzt deine eigenen Daten ein.')
  }

  // Stammdaten speichern - bei ök2: Demo-Stammdaten (inkl. Mein Weg) in k2-oeffentlich-stammdaten-*; bei VK2 in k2-vk2-stammdaten; K2: echte Stammdaten
  const saveStammdaten = () => {
    return new Promise<void>((resolve, reject) => {
      if (tenant.isOeffentlich) {
        try {
          const { welcomeImage: _w, galerieCardImage: _c, virtualTourImage: _v, ...galleryStammdaten } = galleryData
          persistStammdaten('oeffentlich', 'martina', martinaData)
          persistStammdaten('oeffentlich', 'georg', georgData)
          persistStammdaten('oeffentlich', 'gallery', { ...galleryStammdaten } as any)
        } catch (e) {
          reject(e)
          return
        }
        resolve()
        return
      }
      if (tenant.isVk2) {
        try {
          saveVk2Stammdaten(vk2Stammdaten)
          resolve()
        } catch (e) {
          reject(e)
        }
        return
      }
      const timeoutId = setTimeout(() => {
        reject(new Error('Speichern dauerte zu lange'))
      }, 5000) // Max 5 Sekunden
      
      try {
        // Stammdaten Galerie: Bilder nicht mitschreiben (leben nur in Seitengestaltung k2-page-content-galerie). Schicht: saveStammdaten.
        const { welcomeImage: _w, galerieCardImage: _c, virtualTourImage: _v, ...galleryStammdaten } = galleryData
        const galleryToSave = galleryStammdaten as typeof galleryData

        const martinaStr = JSON.stringify(martinaData)
        const georgStr = JSON.stringify(georgData)
        const galleryStr = JSON.stringify(galleryToSave)
        if (martinaStr.length > 100000 || georgStr.length > 100000 || galleryStr.length > 5000000) {
          clearTimeout(timeoutId)
          reject(new Error('Daten zu groß zum Speichern'))
          return
        }

        persistStammdaten('k2', 'martina', martinaData)
        persistStammdaten('k2', 'georg', georgData)
        persistStammdaten('k2', 'gallery', galleryToSave)
        
        clearTimeout(timeoutId)
        resolve()
      } catch (error) {
        clearTimeout(timeoutId)
        reject(error)
      }
    })
  }

  // Mobile Version veröffentlichen - Daten speichern + JSON-Datei erstellen + Vercel öffnen
  const [isDeploying, setIsDeploying] = React.useState(false)
  const [publishErrorMsg, setPublishErrorMsg] = React.useState<string | null>(null)
  const [publishSuccessModal, setPublishSuccessModal] = React.useState<{
    size: number
    version: number
    artworksCount?: number
    imagesResolved?: number
    artworkNumbersWithoutImageUrl?: string[]
    serverArtworksCount?: number
    serverImagesCount?: number
    serverExportedAt?: string
  } | null>(null)
  /** Balken für Senden/Empfangen: phase idle | sending | loading | success | error – Nutzer sieht sofort was passiert */
  const [syncStatusBar, setSyncStatusBar] = React.useState<{ phase: 'idle' | 'sending' | 'loading' | 'success' | 'error'; message: string }>({ phase: 'idle', message: '' })
  /** Zeitstempel im Sync-Fenster: Zuletzt geladen / Zuletzt gesendet (aus localStorage, K2) */
  const [lastSyncLoadedAt, setLastSyncLoadedAt] = React.useState<string | null>(() => {
    try { return typeof localStorage !== 'undefined' ? localStorage.getItem('k2-last-loaded-timestamp') : null } catch { return null }
  })
  const [lastSyncSentAt, setLastSyncSentAt] = React.useState<string | null>(() => {
    try { return typeof localStorage !== 'undefined' ? localStorage.getItem('k2-last-sent-timestamp') : null } catch { return null }
  })

  // SICHERHEIT: Stelle sicher dass isDeploying nach 60 Sekunden zurückgesetzt wird
  React.useEffect(() => {
    if (isDeploying) {
      const safetyTimeout = setTimeout(() => {
        if (isMountedRef.current) {
          console.warn('⚠️ isDeploying wurde nach 60 Sekunden automatisch zurückgesetzt')
          setIsDeploying(false)
        }
      }, 60000) // 60 Sekunden Safety-Timeout
      
      return () => {
        clearTimeout(safetyTimeout)
        // Kein setState im Cleanup – verhindert Crash/Warning bei Unmount
      }
    }
  }, [isDeploying])

  // Sync-Statusbalken: Erfolg/Fehler nach 5 Sekunden wieder ausblenden
  React.useEffect(() => {
    if (syncStatusBar.phase !== 'success' && syncStatusBar.phase !== 'error') return
    const t = setTimeout(() => {
      if (isMountedRef.current) setSyncStatusBar({ phase: 'idle', message: '' })
    }, 5000)
    return () => clearTimeout(t)
  }, [syncStatusBar.phase])

  // Zeitstempel im Sync-Fenster: aktualisieren wenn anderer Tab (z. B. Galerie-Vorschau) geladen/gesendet hat
  React.useEffect(() => {
    const onStorage = (e: StorageEvent) => {
      if (e.key === 'k2-last-loaded-timestamp' && e.newValue) setLastSyncLoadedAt(e.newValue)
      if (e.key === 'k2-last-sent-timestamp' && e.newValue) setLastSyncSentAt(e.newValue)
    }
    window.addEventListener('storage', onStorage)
    return () => window.removeEventListener('storage', onStorage)
  }, [])
  
  // KEINE automatische Prüfung mehr - verursacht Abstürze!
  // Verwende nur den manuellen "🔍 Vercel-Status" Button
  
  // Manueller Vercel-Check-Button
  const [checkingVercel, setCheckingVercel] = React.useState(false)
  
  // MINIMALE Vercel-Prüfung - MIT TIMEOUT UND CRASH-SCHUTZ (setState nur wenn gemountet)
  const manualCheckVercel = () => {
    if (checkingVercel) return
    
    setCheckingVercel(true)
    
    // Timeout nach 10 Sekunden - verhindert Hänger
    const timeoutId = setTimeout(() => {
      if (!isMountedRef.current) return
      setCheckingVercel(false)
      alert('⚠️ Vercel-Check:\n\nTimeout nach 10 Sekunden\n\nPrüfe manuell: https://vercel.com/dashboard → Projekt k2-galerie')
    }, 10000)
    
    try {
      // Fetch mit Timeout
      const controller = new AbortController()
      const fetchTimeout = setTimeout(() => controller.abort(), 8000) // 8 Sekunden Timeout
      
      fetch('https://k2-galerie.vercel.app/gallery-data.json?t=' + Date.now(), {
        signal: controller.signal
      })
        .then(response => {
          clearTimeout(fetchTimeout)
          clearTimeout(timeoutId)
          if (response.ok) {
            return response.json()
          }
          throw new Error('HTTP ' + response.status)
        })
        .then(data => {
          if (!isMountedRef.current) return
          const exportedAt = data?.exportedAt || 'nicht gefunden'
          alert(`✅ Vercel-Status:\n\nDatei verfügbar\nExportedAt: ${exportedAt}\n\nPrüfe: https://vercel.com/dashboard → k2-galerie`)
        })
        .catch(err => {
          clearTimeout(fetchTimeout)
          clearTimeout(timeoutId)
          if (!isMountedRef.current) return
          if (err.name === 'AbortError') {
            alert('⚠️ Vercel-Check:\n\nTimeout - Anfrage dauerte zu lange\n\nPrüfe: https://vercel.com/dashboard → k2-galerie')
          } else {
            alert('⚠️ Vercel-Check:\n\nDatei nicht verfügbar\n\nPrüfe: https://vercel.com/dashboard → k2-galerie')
          }
        })
        .finally(() => {
          clearTimeout(fetchTimeout)
          clearTimeout(timeoutId)
          if (isMountedRef.current) setCheckingVercel(false)
        })
    } catch (error) {
      clearTimeout(timeoutId)
      if (isMountedRef.current) setCheckingVercel(false)
      alert('⚠️ Vercel-Check Fehler:\n\n' + (error instanceof Error ? error.message : String(error)))
    }
  }
  
  // KEINE automatische Prüfung mehr - verursacht Abstürze!
  // Verwende nur den manuellen "🔍 Vercel-Status" Button
  
  /** Vollbackup (Stammdaten + Werke + Eventplanung + Öffentlichkeitsarbeit) als JSON herunterladen – für Sicherung */
  const downloadFullBackup = () => {
    try {
      const getItemSafe = (key: string, def: any) => {
        try {
          const item = localStorage.getItem(key)
          if (!item || item.length > 1000000) return def
          return JSON.parse(item)
        } catch { return def }
      }
      const eventsForBackup = (Array.isArray(events) && events.length > 0) ? events : loadEventsFromStorage('k2')
      const documentsForBackup = (Array.isArray(documents) && documents.length > 0) ? documents : loadDocumentsFromStorage('k2')
      const customersForBackup = getItemSafe('k2-customers', []) || []
      let pageContentGalerieRaw: string | undefined
      try {
        const raw = localStorage.getItem('k2-page-content-galerie')
        if (raw && raw.length < 6 * 1024 * 1024) pageContentGalerieRaw = raw
      } catch (_) {}
      // Immer volle Werke aus localStorage (in iframe ist allArtworks „leicht“ ohne Base64 – Backup muss voll sein)
      const artworksForBackup = loadArtworks(tenant)
      const payload = {
        martina: martinaData,
        georg: georgData,
        gallery: galleryData,
        artworks: artworksForBackup,
        events: eventsForBackup,
        documents: documentsForBackup,
        customers: Array.isArray(customersForBackup) ? customersForBackup : [],
        designSettings: getItemSafe(getDesignStorageKey(), {}),
        pageTexts: getItemSafe('k2-page-texts', null),
        pageContentGalerie: pageContentGalerieRaw,
        exportedAt: new Date().toISOString(),
        backupLabel: 'K2 Vollbackup (Stammdaten, Werke, Eventplanung, Öffentlichkeitsarbeit, Kunden, Seitengestaltung)'
      }
      const json = JSON.stringify(payload, null, 2)
      const blob = new Blob([json], { type: 'application/json' })
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `k2-vollbackup-${new Date().toISOString().slice(0, 10)}-${Date.now()}.json`
      a.style.display = 'none'
      document.body.appendChild(a)
      a.click()
      setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url) }, 200)
      const customersCount = Array.isArray(customersForBackup) ? customersForBackup.length : 0
      alert(`✅ Sicherungskopie wurde heruntergeladen.\n\nIn der Datei sind: Stammdaten, ${artworksForBackup.length} Werke, ${eventsForBackup.length} Events, ${documentsForBackup.length} Dokumente, ${customersCount} Kunden.\n\nSpeichere die Datei an einem sicheren Ort (z. B. PC, USB-Stick). Falls du später Daten verlierst oder auf einem neuen Gerät startest, kannst du sie hier mit „Aus Backup-Datei wiederherstellen“ wieder einspielen.`)
    } catch (e) {
      alert('Die Sicherungskopie konnte nicht erstellt werden.\n\nGrund: ' + (e instanceof Error ? e.message : String(e)) + '\n\nBitte erneut versuchen. Wenn es wieder fehlschlägt, Speicher prüfen („Speicher freigeben“) oder den Assistenten fragen.')
    }
  }
  
  /** options.silent = true: kein isDeploying, kein Erfolgs-Alert – für automatisches Sync nach Speichern (zentrale Stelle Vercel) */
  const publishMobile = (options?: { silent?: boolean }) => {
    const silent = options?.silent === true
    if (!silent && isDeploying) return
    // Tenantfähig: Veröffentlichen für K2, ök2 und VK2 (jeweils eigener Blob auf dem Server)
    if (!isMountedRef.current) {
      if (!silent) console.warn('⚠️ publishMobile: Component ist unmounted')
      return
    }
    if (!silent) {
      setIsDeploying(true)
      setSyncStatusBar({ phase: 'sending', message: 'Daten werden gesendet…' })
    }
    
    // KOMPLETT NEUE LÖSUNG: Web Worker für JSON.stringify um UI nicht zu blockieren
    const executeExport = () => {
      try {
        const getItemSafe = (key: string, defaultValue: any) => {
          try {
            const item = localStorage.getItem(key)
            if (!item || item.length > 1000000) return defaultValue // Max 1MB pro Item
            return JSON.parse(item)
          } catch {
            return defaultValue
          }
        }

        // VK2: eigener Export (Stammdaten, Events, Dokumente, Design – keine Werke)
        if (tenant.isVk2) {
          const { data: vk2Data, filename: _fn } = createVk2Backup()
          const data = { ...vk2Data, tenantId: 'vk2' }
          const json = JSON.stringify(data)
          if (json.length > 5000000) {
            if (isMountedRef.current && !silent) setIsDeploying(false)
            if (!silent) alert('⚠️ Daten zu groß. Bitte reduzieren.')
            return
          }
          apiPost(WRITE_GALLERY_DATA_API_URL, json, { timeoutMs: 30000 }).then(result => {
            if (!silent && isMountedRef.current) setIsDeploying(false)
            if (result.success && result.data) {
              if (silent) console.log('✅ VK2-Daten an Server gesendet')
              else {
                setSyncStatusBar({ phase: 'success', message: 'Gesendet.' })
                setPublishSuccessModal({ size: json.length, version: 1 })
              }
            } else {
              if (!silent) {
                setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
                setPublishErrorMsg(result.error || 'VK2-Daten konnten nicht gesendet werden.')
              }
            }
          }).finally(() => { if (isMountedRef.current && !silent) setIsDeploying(false) })
          return
        }

        // Dynamischer Mandant (?tenantId=): nur State → API, kein localStorage
        if (tenant.dynamicTenantId) {
          const exportedAt = new Date().toISOString()
          const artworksForDyn = sortArtworksFavoritesFirstThenNewest(Array.isArray(allArtworks) ? [...allArtworks] : [])
          const pageContentGalerieRaw = typeof pageContent === 'object' && pageContent != null ? JSON.stringify(pageContent) : undefined
          const data = {
            martina: martinaData || {},
            georg: georgData || {},
            gallery: galleryData || {},
            artworks: artworksForDyn,
            events: Array.isArray(events) ? events.slice(0, 100) : [],
            documents: Array.isArray(documents) ? documents.slice(0, 100) : [],
            designSettings: designSettings || {},
            pageTexts: pageTexts ?? {},
            pageContentGalerie: pageContentGalerieRaw,
            exportedAt,
            version: 1,
            buildId: `${Date.now()}-${Math.random().toString(36).substring(7)}`,
            tenantId: tenant.dynamicTenantId,
          }
          const json = JSON.stringify(data)
          if (json.length > 5000000) {
            if (isMountedRef.current && !silent) setIsDeploying(false)
            if (!silent) alert('⚠️ Daten zu groß. Bitte reduzieren.')
            return
          }
          apiPost(WRITE_GALLERY_DATA_API_URL, json, { timeoutMs: 30000 }).then(result => {
            if (!silent && isMountedRef.current) setIsDeploying(false)
            if (result.success && result.data) {
              if (silent) console.log('✅ Galerie-Daten gespeichert (Mandant)', tenant.dynamicTenantId)
              else {
                setSyncStatusBar({ phase: 'success', message: 'Gesendet.' })
                setPublishSuccessModal({ size: json.length, version: 1 })
              }
            } else {
              if (!silent) {
                setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
                setPublishErrorMsg(result.error || 'Daten konnten nicht gespeichert werden.')
              }
            }
          }).finally(() => { if (isMountedRef.current && !silent) setIsDeploying(false) })
          return
        }
        
        // K2 / ök2: Werke inkl. Mobile-Werke für Synchronisation
        const artworksKey = tenant.getArtworksKey()
        let artworks = getItemSafe(artworksKey, [])
        
        // WICHTIG: Prüfe ob Werke vorhanden sind
        if (!Array.isArray(artworks) || artworks.length === 0) {
          console.warn('⚠️ WARNUNG: Keine Werke gefunden in localStorage!')
          console.log('localStorage', artworksKey + ':', localStorage.getItem(artworksKey)?.substring(0, 200))
          
          // Versuche alternative Methode
          try {
            const stored = localStorage.getItem(artworksKey)
            if (stored) {
              artworks = JSON.parse(stored)
              console.log('✅ Werke geladen via alternative Methode:', artworks.length)
            }
          } catch (e) {
            console.error('❌ Fehler beim Laden der Werke:', e)
          }
        }
        
        // WICHTIG: Prüfe ob Mobile-Werke vorhanden sind und stelle sicher dass sie mit exportiert werden
        const mobileWorks = artworks.filter((a: any) => a.createdOnMobile || a.updatedOnMobile)
        if (mobileWorks.length > 0) {
          console.log(`📱 ${mobileWorks.length} Mobile-Werke werden mit exportiert:`, mobileWorks.map((a: any) => a.number || a.id).join(', '))
        }
        
        // K2: Export nur wenn Werke vorhanden. ök2: 0 Werke erlaubt (z. B. Test-Galerie leer).
        const _artworksCheck = getItemSafe(artworksKey, [])
        const hasArtworksInState = Array.isArray(artworks) && artworks.length > 0
        const hasArtworksInStorage = Array.isArray(_artworksCheck) && _artworksCheck.length > 0
        if (!tenant.isOeffentlich && !hasArtworksInState && !hasArtworksInStorage) {
          if (isMountedRef.current && !silent) setIsDeploying(false)
          if (!silent) alert('⚠️ KEINE WERKE GEFUNDEN!\n\nBitte zuerst Werke speichern bevor veröffentlicht wird.\n\n📋 Prüfe:\n1. Sind Werke in "Werke verwalten" vorhanden?\n2. Werden Werke korrekt gespeichert?\n3. Prüfe Browser-Konsole für Fehler')
          return
        }
        
        // REGEL: Beim Veröffentlichen immer den aktuellen Admin-State verwenden (was du siehst, geht raus).
        // Fallback localStorage, dann Merge – keine halbe Lieferung. Alle geänderten Daten müssen mit.
        const exportedAt = new Date().toISOString()
        const currentVersion = parseInt(localStorage.getItem('k2-data-version') || '0')
        const newVersion = currentVersion + 1
        localStorage.setItem('k2-data-version', newVersion.toString())

        const stammTenant = tenant.isOeffentlich ? ('oeffentlich' as const) : ('k2' as const)
        const martinaStored = loadStammdaten(stammTenant, 'martina') as Record<string, unknown>
        const georgStored = loadStammdaten(stammTenant, 'georg') as Record<string, unknown>
        const galleryStamm = loadStammdaten(stammTenant, 'gallery') as Record<string, unknown>
        const oeffentlich = tenant.isOeffentlich
        const pageContentStored = getPageContentGalerie(oeffentlich ? 'oeffentlich' : undefined)
        const eventsStored = getItemSafe(tenant.getEventsKey(), []) || []
        const documentsStored = getItemSafe(tenant.getDocumentsKey(), []) || []
        const artworksStored = getItemSafe(tenant.getArtworksKey(), []) || []
        const designStored = getItemSafe(getDesignStorageKey(), {})
        const pageTextsStored = getItemSafe(oeffentlich ? 'k2-oeffentlich-page-texts' : 'k2-page-texts', null)

        const martinaExport = (martinaData && typeof martinaData === 'object' && Object.keys(martinaData).length > 0) ? { ...martinaStored, ...martinaData } : martinaStored
        const georgExport = (georgData && typeof georgData === 'object' && Object.keys(georgData).length > 0) ? { ...georgStored, ...georgData } : georgStored
        const galleryMerged = { ...galleryStamm, ...(galleryData || {}) }
        const galleryExport = {
          ...galleryMerged,
          // pageContentStored hat Priorität – dort landen die per Admin hochgeladenen Bilder
          welcomeImage: pageContentStored.welcomeImage || galleryData?.welcomeImage || galleryStamm.welcomeImage || '',
          galerieCardImage: pageContentStored.galerieCardImage || galleryData?.galerieCardImage || galleryStamm.galerieCardImage || '',
          virtualTourImage: pageContentStored.virtualTourImage || galleryData?.virtualTourImage || galleryStamm.virtualTourImage || ''
        }
        const designExport = (designSettings && typeof designSettings === 'object' && Object.keys(designSettings).length > 0) ? designSettings : designStored
        const pageTextsExport = (pageTexts != null && typeof pageTexts === 'object') ? pageTexts : pageTextsStored
        let pageContentGalerieRaw: string | undefined
        try {
          const raw = localStorage.getItem(oeffentlich ? 'k2-oeffentlich-page-content-galerie' : 'k2-page-content-galerie')
          if (raw && raw.length > 0 && raw.length < 6 * 1024 * 1024) pageContentGalerieRaw = raw
        } catch (_) {}
        const eventsMerged = Array.isArray(events) && events.length > 0 ? events : eventsStored
        const documentsMerged = Array.isArray(documents) && documents.length > 0 ? documents : documentsStored
        const maxList = 100
        const eventsForExport = Array.isArray(eventsMerged) ? eventsMerged.slice(0, maxList) : []
        const documentsForExport = Array.isArray(documentsMerged) ? documentsMerged.slice(0, maxList) : []
        // Admin-State hat Priorität (was du siehst, geht raus); Fallback localStorage
        const artworksState = (allArtworksRef.current && allArtworksRef.current.length > 0) ? allArtworksRef.current : (Array.isArray(artworks) ? artworks : [])
        const artworksById = new Map<string, any>()
        artworksStored.forEach((a: any) => { const k = a?.number || a?.id; if (k) artworksById.set(String(k), a) })
        artworksState.forEach((a: any) => { const k = a?.number || a?.id; if (k) artworksById.set(String(k), a) })
        const artworksForExport = sortArtworksFavoritesFirstThenNewest(Array.from(artworksById.values()))

        // K2: Prozesssicherheit – nur zentraler Ablauf (publishGalleryDataToServer). Sportwagenmodus: ImageStore.
        if (!tenant.isOeffentlich && !tenant.isVk2) {
          try {
            saveArtworksByKeyWithImageStore('k2-artworks', artworksForExport, { filterK2Only: true, allowReduce: false }).then(async (saved) => {
              if (!saved) { if (isMountedRef.current && !silent) setIsDeploying(false); if (!silent) alert('Fehler beim Speichern'); return }
              persistStammdaten('k2', 'martina', martinaExport as Record<string, unknown>)
              persistStammdaten('k2', 'georg', georgExport as Record<string, unknown>)
              persistStammdaten('k2', 'gallery', galleryExport as Record<string, unknown>)
              saveEventsToStorage('k2', eventsForExport)
              saveDocumentsToStorage('k2', documentsForExport)
              localStorage.setItem('k2-design-settings', JSON.stringify(designExport))
              if (pageTextsExport != null) localStorage.setItem('k2-page-texts', JSON.stringify(pageTextsExport))
              if (pageContentGalerieRaw != null && pageContentGalerieRaw.length > 0) localStorage.setItem('k2-page-content-galerie', pageContentGalerieRaw)
              // Mit aufgelösten Bildern veröffentlichen (30–48 etc.), sonst fehlen Bild-URLs am Server und auf anderen Geräten
              const raw = readArtworksRawByKey('k2-artworks')
              const toPublish = await resolveArtworkImages(raw)
              publishGalleryDataToServer(toPublish, {
                onProgress: (done, total, phase) => {
                  if (!silent && isMountedRef.current) {
                    const msg = phase === 'chunks' ? `Teil ${done} von ${total} wird gesendet …` : (total > 1 ? `Bilder vorbereiten … ${done}/${total}` : 'Daten werden gesendet…')
                    setSyncStatusBar({ phase: 'sending', message: msg })
                  }
                }
              }).then((result) => {
              if (!isMountedRef.current) return
              if (!silent) setIsDeploying(false)
              if (result.success) {
                const sentAt = new Date().toISOString()
                try { localStorage.setItem('k2-last-sent-timestamp', sentAt) } catch (_) {}
                setLastSyncSentAt(sentAt)
                if (silent) {
                  console.log('✅ K2-Daten an Server (zentral):', result.artworksCount, 'Werke', result.serverArtworksCount != null ? `| Vercel: ${result.serverArtworksCount} Werke, ${result.serverImagesCount} mit Bild` : '')
                  setSyncStatusBar({ phase: 'success', message: 'Gespeichert & an Vercel gesendet.' })
                  setTimeout(() => { if (isMountedRef.current) setSyncStatusBar((prev) => (prev.phase === 'success' && prev.message?.includes('Gespeichert & an Vercel') ? { phase: 'idle', message: '' } : prev)) }, 4000)
                } else {
                  setSyncStatusBar({ phase: 'success', message: 'Gesendet.' })
                  setPublishSuccessModal({
                    size: result.result?.size ?? 0,
                    version: parseInt(localStorage.getItem('k2-data-version') || '0', 10) + 1,
                    artworksCount: result.artworksCount,
                    imagesResolved: result.imagesResolved,
                    artworkNumbersWithoutImageUrl: result.artworkNumbersWithoutImageUrl,
                    serverArtworksCount: result.serverArtworksCount,
                    serverImagesCount: result.serverImagesCount,
                    serverExportedAt: result.serverExportedAt
                  })
                }
              } else {
                if (!silent) {
                  setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
                  setPublishErrorMsg(result.error || 'Daten konnten nicht gesendet werden.')
                } else {
                  console.warn('Sync (silent) fehlgeschlagen:', result.error)
                  setSyncStatusBar({ phase: 'error', message: 'Gespeichert. Hochladen an Vercel fehlgeschlagen.' })
                }
              }
            }).catch((e) => {
              if (isMountedRef.current && !silent) setIsDeploying(false)
              if (!silent) {
                setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
                setPublishErrorMsg(e instanceof Error ? e.message : String(e))
              } else {
                console.warn('Sync (silent) Fehler:', e)
                setSyncStatusBar({ phase: 'error', message: 'Gespeichert. Hochladen an Vercel fehlgeschlagen.' })
              }
            }).finally(() => { if (isMountedRef.current && !silent) setIsDeploying(false) })
            })
          } catch (e) {
            if (isMountedRef.current && !silent) setIsDeploying(false)
            if (!silent) alert('Fehler beim Vorbereiten: ' + (e instanceof Error ? e.message : String(e)))
            else console.warn('K2 Publish Vorbereitung:', e)
          }
          return
        }

        const data = {
          martina: martinaExport,
          georg: georgExport,
          gallery: galleryExport,
          artworks: artworksForExport,
          events: eventsForExport,
          documents: documentsForExport,
          designSettings: designExport,
          pageTexts: pageTextsExport,
          pageContentGalerie: pageContentGalerieRaw,
          exportedAt: exportedAt,
          version: newVersion,
          buildId: `${Date.now()}-${Math.random().toString(36).substring(7)}`,
          tenantId: tenant.isOeffentlich ? 'oeffentlich' : 'k2'
        }
        
        // K2: Mindestens ein Werk nötig. ök2: 0 Werke erlaubt.
        if (!tenant.isOeffentlich && (!data.artworks || data.artworks.length === 0)) {
          console.error('❌ FEHLER: Keine Werke im Export-Objekt!', { dataKeys: Object.keys(data) })
          if (isMountedRef.current && !silent) setIsDeploying(false)
          if (!silent) alert('⚠️ FEHLER: Keine Werke im Export!\n\nBitte prüfe Browser-Konsole für Details.')
          return
        }
        
        console.log(`✅ Export vorbereitet: ${data.artworks?.length ?? 0} Werke, tenantId=${data.tenantId}`)
        
        // JSON.stringify in separatem Frame mit Progress-Check
        const stringifyData = () => {
          try {
            const json = JSON.stringify(data)
            if (json.length > 5000000) { // Max 5MB
              if (isMountedRef.current && !silent) setIsDeploying(false)
              if (!silent) alert('⚠️ Daten zu groß. Bitte reduziere die Anzahl der Werke.')
              return
            }
            
            // Phase 2.2: Ein API-Client (Timeout, einheitliche Rückgabe)
            apiPost(WRITE_GALLERY_DATA_API_URL, json, { timeoutMs: 30000 }).then(result => {
              if (!silent && isMountedRef.current) setIsDeploying(false)
              if (result.success && result.data) {
                const sentAt = new Date().toISOString()
                try { localStorage.setItem('k2-last-sent-timestamp', sentAt) } catch (_) {}
                setLastSyncSentAt(sentAt)
                const payload = (result.data as { size?: number; artworksCount?: number }) || {}
                const newVersion = parseInt(localStorage.getItem('k2-data-version') || '0') + 1
                localStorage.setItem('k2-data-version', String(newVersion))
                if (silent) {
                  console.log('✅ Daten an Vercel gesendet:', payload.size, 'Bytes,', payload.artworksCount, 'Werke')
                } else {
                  setSyncStatusBar({ phase: 'success', message: 'Gesendet.' })
                  setPublishSuccessModal({ size: payload.size ?? 0, version: newVersion })
                }
                return
              }
              const errMsg = result.error || 'Unbekannter Fehler'
              const hint = result.hint ? `\n\n${result.hint}` : ''
              if (!silent) {
                setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
                setPublishErrorMsg(`Daten konnten nicht gesendet werden.\n\n${errMsg}${hint}`)
              } else {
                console.warn('Sync (silent) fehlgeschlagen:', errMsg)
              }
              if (silent) return
              const isVercelOrProduction = typeof window !== 'undefined' && window.location.hostname !== 'localhost' && window.location.hostname !== '127.0.0.1'
              const isMobileDevice = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent) || (typeof navigator !== 'undefined' && navigator.maxTouchPoints > 0 && typeof window !== 'undefined' && window.innerWidth <= 1024)
              if (isVercelOrProduction || isMobileDevice) {
                if (isMountedRef.current) setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
                const detail = (errMsg + (result.hint ? ' ' + result.hint : '')).trim()
                alert('⚠️ Daten konnten nicht an den Server gesendet werden.\n\n' + (detail ? 'Grund: ' + detail + '\n\n' : '') + 'Bitte prüfen: App von k2-galerie.vercel.app geöffnet? Internet verbunden? Steht „Blob-Speicher nicht eingerichtet“ → in Vercel unter Storage einen Blob Store anlegen (siehe Doku).\n\nEinfach OK – du bleibst in der App.')
                return
              }
              try {
                const blob = new Blob([json], { type: 'application/json' })
                const url = URL.createObjectURL(blob)
                const link = document.createElement('a')
                link.href = url
                link.download = 'gallery-data.json'
                link.style.display = 'none'
                document.body.appendChild(link)
                link.click()
                if (isMountedRef.current) setIsDeploying(false)
                setTimeout(() => {
                  try { document.body.removeChild(link); URL.revokeObjectURL(url) } catch {}
                  setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
                  alert('⚠️ Automatisches Speichern nicht möglich (Server nicht aktiv).\n\nBitte dem Assistenten Bescheid geben – einmalige Einrichtung nötig.')
                }, 100)
              } catch (downloadError) {
                if (isMountedRef.current) setIsDeploying(false)
                setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
                alert('❌ Fehler:\n\nAPI nicht verfügbar UND Download fehlgeschlagen\n\n' + errMsg)
              }
            }).finally(() => {
              setTimeout(() => { if (isMountedRef.current && !silent) setIsDeploying(false) }, 100)
            })
          } catch (e) {
            if (isMountedRef.current && !silent) {
              setIsDeploying(false)
              setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
            }
            if (!silent) alert('Fehler: ' + (e instanceof Error ? e.message : String(e)))
            else console.warn('Sync (silent) Fehler:', e)
          }
        }
        
        if (typeof window.requestIdleCallback !== 'undefined') {
          window.requestIdleCallback(stringifyData, { timeout: 5000 })
        } else {
          setTimeout(stringifyData, 100)
        }
      } catch (error) {
        if (isMountedRef.current && !silent) {
          setIsDeploying(false)
          setSyncStatusBar({ phase: 'error', message: 'Fehler beim Senden.' })
        }
        if (!silent) alert('Fehler: ' + (error instanceof Error ? error.message : String(error)))
        else console.warn('Sync (silent) Fehler:', error)
      }
    }
    
    const executeTimeout = setTimeout(() => {
      if (isMountedRef.current) {
        executeExport()
      } else {
        if (isMountedRef.current && !silent) setIsDeploying(false)
      }
    }, 50)
    
    // SICHERHEIT: Stelle sicher dass isDeploying nach max 60 Sekunden zurückgesetzt wird - MIT Cleanup
    // WICHTIG: Dieser Timeout wird durch den useEffect oben bereits abgedeckt, daher nicht nochmal hier
    
    // Cleanup Timeouts beim Unmount - WICHTIG: publishMobile ist keine useEffect, daher kein return
    // Die Timeouts werden durch isMountedRef.current geschützt
  }

  // Automatisch Künstler basierend auf Kategorie setzen - NUR wenn Kategorie sich ändert
  useEffect(() => {
    let isMounted = true
    // Warte kurz damit Daten geladen sind
    const timeoutId = setTimeout(() => {
      if (!isMounted) return
      try {
        // Prüfe nur wenn Kategorie sich ändert, nicht wenn Artist sich ändert
        // Künstler je nach Kategorie (max 5): Martina = Bilder/Grafik/Sonstiges, Georg = Keramik/Skulptur
        if ((artworkCategory === 'malerei' || artworkCategory === 'grafik' || artworkCategory === 'sonstiges') && martinaData?.name) {
          setArtworkArtist(martinaData.name)
        } else if ((artworkCategory === 'keramik' || artworkCategory === 'skulptur') && georgData?.name) {
          setArtworkArtist(georgData.name)
        }
      } catch (error) {
        // Ignoriere Fehler um Crashes zu vermeiden
        console.warn('Fehler beim Setzen des Künstlers:', error)
      }
    }, 500) // Warte bis Daten geladen sind
    
    return () => {
      isMounted = false
      clearTimeout(timeoutId)
    }
  }, [artworkCategory]) // NUR Kategorie - verhindert Render-Loop!

  // Letzte Kategorie merken: beim Öffnen „Neues Werk“ wiederherstellen (Serien-Eingabe). ök2: nicht überschreiben – Richtung setzt Defaults.
  const K2_LAST_ARTWORK_CATEGORY_KEY = 'k2-last-artwork-category'
  useEffect(() => {
    if (showAddModal && !editingArtwork && !tenant.isOeffentlich) {
      try {
        const last = localStorage.getItem(K2_LAST_ARTWORK_CATEGORY_KEY)
        if (last && (ARTWORK_CATEGORIES.some((c) => c.id === last) || (tenant.isVk2 && getVk2Kunstrichtungen(vk2Stammdaten).some((c) => c.id === last)))) {
          setArtworkCategory(last)
        }
      } catch (_) {}
    }
  }, [showAddModal, editingArtwork])

  // ök2: Nach Speichern der Richtung in Stammdaten – nur „Typ“ für Werkkatalog; Kategorie bleibt Nutzerwahl nicht aus Stammdaten überschreiben (Grund: siehe Reset bei Tab/Modal).
  useEffect(() => {
    if (!tenant.isOeffentlich) return
    const dirs = galleryData?.focusDirections
    const effective = Array.isArray(dirs) && dirs.length > 0 ? dirs : [DEFAULT_OEK2_FOCUS_DIRECTION_ID]
    const typ = getDefaultEntryTypeForFocusDirections(effective)
    setEntryTypeFilter(typ)
  }, [tenant.isOeffentlich, galleryData?.focusDirections])

  /** Werke verwalten: Kategorie-Filter immer wieder „Alle“, wenn man zur Listenansicht zurückkommt – sonst wirkt es wie „Werke weg“. */
  const prevActiveTabForCategoryRef = useRef<string | null>(null)
  useEffect(() => {
    if (activeTab === 'werke' && prevActiveTabForCategoryRef.current != null && prevActiveTabForCategoryRef.current !== 'werke') {
      setCategoryFilter('alle')
    }
    prevActiveTabForCategoryRef.current = activeTab
  }, [activeTab])

  const prevShowAddModalForCategoryRef = useRef(showAddModal)
  useEffect(() => {
    if (prevShowAddModalForCategoryRef.current && !showAddModal) {
      setCategoryFilter('alle')
    }
    prevShowAddModalForCategoryRef.current = showAddModal
  }, [showAddModal])

  // ök2: Beim Öffnen „Neues Werk“ Sparte (Typ) und Kategorie aus gespeicherter Richtung vorausfüllen.
  useEffect(() => {
    if (!showAddModal || editingArtwork || !tenant.isOeffentlich) return
    const dirs = galleryData?.focusDirections
    const dir = Array.isArray(dirs) && dirs.length > 0 ? dirs[0] : DEFAULT_OEK2_FOCUS_DIRECTION_ID
    setArtworkDirection(dir)
    setArtworkEntryType(getEntryTypeForDirection(dir))
    const cats = getCategoriesForDirection(dir)
    setArtworkCategory(cats[0]?.id ?? 'malerei')
  }, [showAddModal, editingArtwork, tenant.isOeffentlich, galleryData?.focusDirections])

  /** In Cursor Preview (iframe) keine schweren Base64-Bilder im State halten → weniger Speicher, weniger Code-5-Crashes */
  const inIframe = typeof window !== 'undefined' && window.self !== window.top
  const stripArtworkImagesForPreview = (list: any[]): any[] => {
    if (!inIframe || !Array.isArray(list)) return list
    return list.map((a: any) => {
      if (a && typeof a.imageUrl === 'string' && a.imageUrl.startsWith('data:')) {
        return { ...a, imageUrl: '' }
      }
      return a
    })
  }
  /** In iframe: data:-URLs in blob:-URLs umwandeln, damit stripArtworkImagesForPreview sie nicht löscht – sonst verschwinden andere Werksbilder beim Speichern eines zweiten. */
  const convertDataUrlsToBlobUrlsInList = async (list: any[]): Promise<any[]> => {
    if (!inIframe || !Array.isArray(list) || list.length === 0) return list
    const out: any[] = []
    for (const a of list) {
      if (!a || typeof a.imageUrl !== 'string' || !a.imageUrl.startsWith('data:')) {
        out.push(a)
        continue
      }
      try {
        const [header, base64] = a.imageUrl.split(',')
        const mime = (header?.match(/data:([^;]+)/)?.[1] || 'image/jpeg').trim()
        const binary = atob(base64 || '')
        const bytes = new Uint8Array(binary.length)
        for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i)
        const blob = new Blob([bytes], { type: mime })
        const url = URL.createObjectURL(blob)
        out.push({ ...a, imageUrl: url })
      } catch {
        out.push(a)
      }
    }
    return out
  }
  /** State setzen – in iframe ohne Base64, um Speicher/Crash 5 zu entlasten. Zuletzt gespeicherte Werke (lastSavedArtworkImageRef) behalten ihr Bild.
   * KRITISCH: Andere Werke behalten ihr imageUrl aus dem aktuellen State – sonst verschwindet das erste Bild, sobald ein zweites geladen/gespeichert wird. */
  const setAllArtworksSafe = (list: any[]) => {
    const arr = Array.isArray(list) ? list : []
    if (inIframe) {
      const stripped = stripArtworkImagesForPreview(arr)
      const last = lastSavedArtworkImageRef.current
      const map = last?.number && last?.imageUrl ? new Map<string, string>([[last.number, last.imageUrl]]) : null
      if (map && map.size > 0) {
        const prevList = allArtworksRef.current || []
        const withSaved = stripped.map((a: any) => {
          if (!a) return a
          const id = String(a?.number ?? a?.id ?? '')
          const url = id ? map.get(id) : null
          if (url) return { ...a, imageUrl: url }
          // Anderes Werk: imageUrl aus aktuellem State erhalten (blob/https), damit erstes Bild nicht verschwindet wenn zweites geladen wird
          const prev = prevList.find((x: any) => String(x?.number ?? x?.id ?? '') === id)
          if (prev?.imageUrl && typeof prev.imageUrl === 'string' && prev.imageUrl.length > 50 && !prev.imageUrl.startsWith('data:'))
            return { ...a, imageUrl: prev.imageUrl }
          return a
        })
        setAllArtworks(withSaved)
        return
      }
      setAllArtworks(stripped)
    } else {
      setAllArtworks(arr)
    }
  }

  // Werke aus localStorage laden – bei Kontextwechsel (K2/ök2/VK2) neu laden, sonst zeigt Admin nach Guide-Klick weiter K2-Daten
  useEffect(() => {
    let isMounted = true
    const t = setTimeout(() => {
      if (!isMounted) return
      try {
        const key = tenant.getArtworksKey()
        const stored = localStorage.getItem(key)
        if (stored && stored.length > 10000000) {
          if (isMounted) setAllArtworks([])
          return
        }
        // ök2: Gespeichert leer = leer anzeigen (kein Rückfall auf Musterwerke bei späterem Re-Run)
        if (tenant.isOeffentlich && stored === '[]') {
          if (isMounted) setAllArtworks([])
          return
        }
        /** K2: Niemals leere Anzeige, wenn localStorage noch Werke hat (z. B. Resolve fehlgeschlagen). */
        const fallbackFromStorageForK2 = () => {
          if (!tenant.isOeffentlich && !tenant.isVk2 && key === 'k2-artworks') {
            const raw = localStorage.getItem('k2-artworks')
            if (raw && raw.length > 2) {
              try {
                const parsed = JSON.parse(raw)
                if (Array.isArray(parsed) && parsed.length > 0) {
                  console.warn('⚠️ Admin: Resolve leer/Fehler, aber k2-artworks hat', parsed.length, 'Werke – zeige aus localStorage')
                  return parsed
                }
              } catch (_) { /* ignore */ }
            }
          }
          return null
        }
        loadArtworksWithResolvedImages(tenant).then(async (artworks) => {
          if (!isMounted) return
          if (Array.isArray(artworks) && artworks.length > 0) {
            if (inIframe) {
              const converted = await convertDataUrlsToBlobUrlsInList(artworks)
              setAllArtworks(converted)
            } else {
              setAllArtworks(artworks)
            }
            return
          }
          const fallback = fallbackFromStorageForK2()
          if (fallback && fallback.length > 0) {
            setAllArtworks(inIframe ? stripArtworkImagesForPreview(fallback) : fallback)
            return
          }
          setAllArtworks(artworks)
        }).catch(() => {
          if (!isMounted) return
          const fallback = fallbackFromStorageForK2()
          if (fallback && fallback.length > 0) {
            setAllArtworks(inIframe ? stripArtworkImagesForPreview(fallback) : fallback)
            return
          }
          setAllArtworks([])
        })
      } catch (_) {
        if (isMounted) {
          const key = tenant.getArtworksKey()
          const fallback = (!tenant.isOeffentlich && !tenant.isVk2 && key === 'k2-artworks') ? (() => {
            try {
              const raw = localStorage.getItem('k2-artworks')
              if (raw && raw.length > 2) {
                const parsed = JSON.parse(raw)
                if (Array.isArray(parsed) && parsed.length > 0) return parsed
              }
            } catch (_) { /* ignore */ }
            return null
          })() : null
          if (fallback && fallback.length > 0) {
            setAllArtworks(inIframe ? stripArtworkImagesForPreview(fallback) : fallback)
          } else {
            setAllArtworks([])
          }
        }
      }
    }, 400)
    return () => { isMounted = false; clearTimeout(t) }
  }, [location.search])
  
  // WICHTIG: Event-Listener für Mobile-Updates (damit Mobile-Werke im Admin angezeigt werden)
  // KRITISCH: K2 nie mit leerer Liste überschreiben – verhindert „alle Werke verschwunden“ nach Speichern
  const allArtworksRef = useRef<any[]>([])
  allArtworksRef.current = allArtworks
  /** Nach eigenem Save kurz ignorieren, damit loadArtworks() (evtl. leer bei großer Liste) die soeben gesetzte Liste nicht überschreibt */
  const ignoreArtworksUpdatedRef = useRef(false)
  /** Mobil: Zuletzt gespeichertes Werkbild hier halten; bei Reload wieder einsetzen, damit es sichtbar bleibt (IDB/Resolve oft langsamer). */
  const lastSavedArtworkImageRef = useRef<{ number: string; imageUrl: string } | null>(null)
  /** Warteschlange: Speichern nacheinander, damit „Bild bei 30“ nicht verloren geht wenn danach 31 gespeichert wird (Lesen nach vorherigem Schreiben). */
  const lastArtworkSaveRef = useRef<Promise<boolean>>(Promise.resolve(true))
  const hasAutoLoadedFromServerRef = useRef(false)
  useEffect(() => {
    const handleArtworksUpdate = (ev: Event) => {
      if (ignoreArtworksUpdatedRef.current) {
        console.log('🔄 artworks-updated ignoriert (gerade selbst gespeichert)')
        return
      }
      console.log('🔄 artworks-updated Event empfangen - lade Werke neu...')
      if (tenant.isOeffentlich && readArtworksRawByKey('k2-oeffentlich-artworks').length === 0) {
        setAllArtworks([])
        return
      }
      const detail = (ev as CustomEvent)?.detail
      if (tenant.getArtworksKey() === 'k2-artworks' && detail?.fromBereinigung) {
        lastSavedArtworkImageRef.current = null
      }
      loadArtworksWithResolvedImages(tenant).then(async (artworks) => {
        if (!tenant.isOeffentlich && !tenant.isVk2 && artworks.length === 0 && allArtworksRef.current.length > 0) {
          console.warn('⚠️ loadArtworks leer, aber Anzeige hat Werke – nicht überschreiben')
          return
        }
        const inIframe = typeof window !== 'undefined' && window.self !== window.top
        let list = inIframe ? await convertDataUrlsToBlobUrlsInList(artworks) : artworks
        // Mobil: Gespeichertes Bild wieder einsetzen, wenn resolve noch leer/Fallback liefert
        const last = lastSavedArtworkImageRef.current
        if (last?.imageUrl && list.length > 0) {
          const id = last.number
          list = list.map((a: any) => {
            if (!a || String(a?.number ?? a?.id ?? '') !== id) return a
            const u = a.imageUrl
            const isFallback = typeof u === 'string' && u.startsWith('https://k2-galerie.vercel.app/img/k2/werk-')
            if (!u || u.length < 50 || isFallback) return { ...a, imageUrl: last.imageUrl }
            return a
          })
        }
        setAllArtworksSafe(list)
      }).catch((error) => { console.error('Fehler beim Neuladen der Werke:', error) })
    }
    
    window.addEventListener('artworks-updated', handleArtworksUpdate)
    
    return () => {
      window.removeEventListener('artworks-updated', handleArtworksUpdate)
    }
  }, [])

  // Sync über Tabs: Wenn k2-artworks in anderem Tab geändert wird (z. B. „Vom Server laden“ in Galerie), Admin neu laden – damit Mac Galerie und Admin gleiche Daten zeigen
  useEffect(() => {
    const artworksKey = tenant.getArtworksKey()
    if (!artworksKey) return
    const onStorage = (e: StorageEvent) => {
      if (e.key !== artworksKey) return
      console.log('🔄 k2-artworks in anderem Tab geändert – Admin lädt Werke neu')
      loadArtworksWithResolvedImages(tenant).then((artworks) => {
        const inIframe = typeof window !== 'undefined' && window.self !== window.top
        let list = inIframe ? artworks.map((a: any) => (a && typeof a?.imageUrl === 'string' && a.imageUrl.startsWith('data:')) ? { ...a, imageUrl: '' } : a) : artworks
        const last = lastSavedArtworkImageRef.current
        if (last?.imageUrl && list.length > 0) {
          const id = last.number
          list = list.map((a: any) => {
            if (!a || String(a?.number ?? a?.id ?? '') !== id) return a
            const u = a.imageUrl
            const isFb = typeof u === 'string' && u.startsWith('https://k2-galerie.vercel.app/img/k2/werk-')
            if (!u || u.length < 50 || isFb) return { ...a, imageUrl: last.imageUrl }
            return a
          })
        }
        const fromStorage = loadArtworks(tenant)
        const withRefs = preserveStorageImageRefs(list, fromStorage, (x: any) => String(x?.number ?? x?.id ?? '').trim())
        setAllArtworksSafe(withRefs)
      }).catch((err) => console.warn('Storage-Reload fehlgeschlagen:', err))
    }
    window.addEventListener('storage', onStorage)
    return () => window.removeEventListener('storage', onStorage)
  }, [tenant])

  // Automatisches Laden: Nach jedem Neuladen (Admin geöffnet) wird einmal still handleLoadFromServer({ silent: true }) ausgeführt (siehe useEffect unten). Galerie-Seite lädt ebenfalls automatisch (GaleriePage loadData nach 1 s).

  /** Tenantfähig: Daten von Vercel laden (K2/ök2: Werke mergen; ök2/VK2: Backup-Format in Keys schreiben; dynamischer Mandant: von API in State). options.silent = true: kein Alert, nur Sync-Balken (für automatisches Laden beim Neuladen). */
  const handleLoadFromServer = async (options?: { silent?: boolean }) => {
    const silent = options?.silent === true
    if (tenant.dynamicTenantId) {
      setIsLoadingFromServer(true)
      setSyncStatusBar({ phase: 'loading', message: 'Daten werden geladen…' })
      const url = `${CENTRAL_GALLERY_DATA_URL}?v=${Date.now()}&tenantId=${encodeURIComponent(tenant.dynamicTenantId)}`
      const result = await apiGet(url, { retryOnce: false })
      setIsLoadingFromServer(false)
      if (!result.success) {
        setSyncStatusBar({ phase: 'error', message: 'Fehler beim Laden.' })
        if (!silent) alert(result.error?.includes('404') ? 'Noch keine Daten auf dem Server.' : (result.error || 'Fehler beim Laden.'))
        return
      }
      const data = (result.data || {}) as Record<string, unknown>
      const apiArtworks = Array.isArray(data.artworks) ? data.artworks : []
      const fromStorage = loadArtworks(tenant)
      const withRefs = preserveStorageImageRefs(apiArtworks, fromStorage, (x: any) => String(x?.number ?? x?.id ?? '').trim())
      setAllArtworksSafe(withRefs)
      if (!tenant.isOeffentlich && !tenant.isVk2) {
        const localDesignRaw = typeof localStorage !== 'undefined' ? localStorage.getItem('k2-design-settings') : null
        const localDesign = localDesignRaw ? (() => { try { return JSON.parse(localDesignRaw) } catch { return null } })() : null
        const localPageTextsRaw = typeof localStorage !== 'undefined' ? localStorage.getItem('k2-page-texts') : null
        const localPageTexts = localPageTextsRaw ? (() => { try { return JSON.parse(localPageTextsRaw) } catch { return null } })() : null
        const toApply = applyServerPayloadK2(data, {
          events: loadEventsFromStorage('k2'),
          documents: loadDocumentsFromStorage('k2'),
          designSettings: localDesign,
          pageTexts: localPageTexts
        })
        setEvents(toApply.events != null ? toApply.events : loadEventsFromStorage('k2'))
        setDocuments(toApply.documents != null ? toApply.documents : loadDocumentsFromStorage('k2'))
        if (toApply.designSettings != null) setDesignSettings(prev => ({ ...prev, ...toApply.designSettings } as any))
        if (toApply.pageTexts != null) setPageTextsState(prev => ({ ...prev, ...toApply.pageTexts } as any))
      } else {
        setEvents(Array.isArray(data.events) ? data.events : [])
        setDocuments(Array.isArray(data.documents) ? data.documents : [])
        if (data.designSettings && typeof data.designSettings === 'object') setDesignSettings(prev => ({ ...prev, ...(data.designSettings as object) } as any))
        if (data.pageTexts && typeof data.pageTexts === 'object') setPageTextsState(prev => ({ ...prev, ...(data.pageTexts as object) } as any))
      }
      if (data.martina && typeof data.martina === 'object') setMartinaData({ ...K2_STAMMDATEN_DEFAULTS.martina, ...data.martina } as any)
      if (data.georg && typeof data.georg === 'object') setGeorgData({ ...K2_STAMMDATEN_DEFAULTS.georg, ...data.georg } as any)
      if (data.gallery && typeof data.gallery === 'object') setGalleryData({ ...K2_STAMMDATEN_DEFAULTS.gallery, ...data.gallery })
      const pc = data.pageContentGalerie ?? data.pageContent
      if (pc != null) {
        const parsed = typeof pc === 'string' ? (() => { try { return JSON.parse(pc) } catch { return {} } })() : pc
        if (typeof parsed === 'object') setPageContent(prev => ({ ...prev, ...parsed }))
      }
      setSyncStatusBar({ phase: 'success', message: 'Geladen.' })
      return
    }
    const tenantId = tenant.isVk2 ? 'vk2' : tenant.isOeffentlich ? 'oeffentlich' : 'k2'
    setIsLoadingFromServer(true)
    setSyncStatusBar({ phase: 'loading', message: 'Daten werden geladen…' })
    const urlPrimary = `${CENTRAL_GALLERY_DATA_URL}?v=${Date.now()}&_=${Math.random()}&tenantId=${tenantId}`
    const urlFallback = tenantId === 'k2' ? `${CENTRAL_GALLERY_DATA_FALLBACK_URL}?v=${Date.now()}&_=${Math.random()}` : null
    const loadTimeoutMs = 60000 // 60 s – viele Werke (z. B. 70) können dauern
    try {
      let result = await apiGet(urlPrimary, { retryOnce: true, timeoutMs: loadTimeoutMs })
      if (urlFallback && !result.success && (result.error?.includes('404') || result.error?.includes('Noch keine'))) {
        result = await apiGet(urlFallback, { retryOnce: true, timeoutMs: loadTimeoutMs })
      }
      if (!result.success) {
        setSyncStatusBar({ phase: 'error', message: 'Fehler beim Laden.' })
        if (!silent) {
          if (tenantId === 'oeffentlich' && result.error?.includes('404')) {
            alert('Für die Demo (ök2) liegt noch kein Stand auf dem Server.\n\nEinmal im ök2-Admin „Daten an Server senden“ klicken – dann wird ein Stand angelegt und „Aktuellen Stand holen“ funktioniert.')
          } else {
            const hint = result.hint ? ` ${result.hint}` : (result.error && result.error.includes('404') ? ' Zuerst „Daten an Server senden“ tippen.' : '')
            alert(`Server: ${result.error || 'Fehler'}.\n\n• App von k2-galerie.vercel.app? Internet verbunden?${hint}`)
          }
        }
        return
      }
      const data = result.data as Record<string, unknown> & { artworks?: unknown[]; exportedAt?: string; kontext?: string }
      if (!data || typeof data !== 'object') {
        setSyncStatusBar({ phase: 'error', message: 'Fehler beim Laden.' })
        if (!silent) alert('Antwort war kein gültiges JSON.')
        return
      }

      // ök2: Server-Daten in k2-oeffentlich-* Keys schreiben (Export- oder Backup-Format)
      // KRITISCH: Niemals K2-Werke in k2-oeffentlich-artworks schreiben (Datentrennung).
      if (tenant.isOeffentlich) {
        const { restoreOek2FromBackup } = await import('../src/utils/autoSave')
        let ok = false
        if (data.kontext === 'oeffentlich' && ('k2-oeffentlich-artworks' in data || 'k2-oeffentlich-stammdaten-martina' in data)) {
          const r = restoreOek2FromBackup(data as Record<string, any>)
          ok = r.ok
        } else {
          // Export-Format (martina, georg, gallery, artworks, …) in Keys überführen
          // Nur artworks übernehmen wenn klar ök2: kontext=oeffentlich oder keine echten K2-Werknummern (0030, K2-K-0030)
          const hasEchteK2Artworks = Array.isArray(data.artworks) && data.artworks.some((a: any) => isEchteK2Werknummer(String(a?.number ?? a?.id ?? '')))
          const allowArtworks = Array.isArray(data.artworks) && (data.kontext === 'oeffentlich' || !hasEchteK2Artworks)
          try {
            const keys: Array<[string, unknown]> = []
            if (allowArtworks) keys.push(['k2-oeffentlich-artworks', data.artworks])
            else if (data.kontext === 'k2' && Array.isArray(data.artworks)) console.warn('⚠️ ök2: Server lieferte K2-Werke – k2-oeffentlich-artworks wird nicht überschrieben (Datentrennung).')
            if (data.martina != null) keys.push(['k2-oeffentlich-stammdaten-martina', data.martina])
            if (data.georg != null) keys.push(['k2-oeffentlich-stammdaten-georg', data.georg])
            if (data.gallery != null) keys.push(['k2-oeffentlich-stammdaten-galerie', data.gallery])
            if (data.events != null) keys.push(['k2-oeffentlich-events', data.events])
            if (data.documents != null) keys.push(['k2-oeffentlich-documents', data.documents])
            if (data.designSettings != null) keys.push(['k2-oeffentlich-design-settings', data.designSettings])
            if (data.pageTexts != null) keys.push(['k2-oeffentlich-page-texts', data.pageTexts])
            if (data.pageContent != null) keys.push(['k2-oeffentlich-page-content-galerie', data.pageContent])
            keys.forEach(([k, v]) => { try { localStorage.setItem(k, typeof v === 'string' ? v : JSON.stringify(v)) } catch (_) {} })
            ok = keys.length > 0
          } catch (_) {}
        }
        if (ok) {
          loadArtworksWithResolvedImages(tenant).then(setAllArtworksSafe)
          window.dispatchEvent(new CustomEvent('artworks-updated', { detail: { fromLocalWrite: true } }))
          setIsLoadingFromServer(false)
          setSyncStatusBar({ phase: 'success', message: 'Geladen.' })
          const exportedAt = data.exportedAt ? ` (Stand: ${new Date(String(data.exportedAt)).toLocaleString('de-AT', { dateStyle: 'short', timeStyle: 'short' })})` : ''
          setTimeout(() => { alert(`✅ Daten vom Server geladen${exportedAt}.`) }, 0)
        } else {
          setIsLoadingFromServer(false)
          setSyncStatusBar({ phase: 'error', message: 'Fehler beim Speichern.' })
          setTimeout(() => { alert('Daten konnten nicht in den Speicher übernommen werden.') }, 0)
        }
        return
      }

      // VK2: Backup-Format vom Server in k2-vk2-* Keys schreiben
      if (tenant.isVk2) {
        const { restoreVk2FromBackup } = await import('../src/utils/autoSave')
        const { ok, restored } = restoreVk2FromBackup(data as Record<string, any>)
        if (ok) {
          setPageContent(getPageContentGalerie('vk2'))
          setPageTextsState(getPageTexts('vk2'))
          setIsLoadingFromServer(false)
          setSyncStatusBar({ phase: 'success', message: 'Geladen.' })
          const exportedAt = data.exportedAt ? ` (Stand: ${new Date(String(data.exportedAt)).toLocaleString('de-AT', { dateStyle: 'short', timeStyle: 'short' })})` : ''
          setTimeout(() => { alert(`✅ VK2-Daten vom Server geladen${exportedAt}.`) }, 0)
        } else {
          setIsLoadingFromServer(false)
          setSyncStatusBar({ phase: 'error', message: 'Fehler beim Speichern.' })
          setTimeout(() => { alert('Daten konnten nicht in den Speicher übernommen werden.') }, 0)
        }
        return
      }

      // K2: Werke mergen wie bisher
      const serverArtworks = filterK2Only(Array.isArray(data.artworks) ? data.artworks : [])
      const serverImagesCount = serverArtworks.filter(
        (a: any) => a?.imageUrl && typeof a.imageUrl === 'string' && (a.imageUrl.startsWith('http://') || a.imageUrl.startsWith('https://'))
      ).length
      const localArtworks = loadArtworksRaw(tenant)
      // SCHUTZ (niemals-kundendaten-loeschen): Server leer oder drastisch weniger → nie überschreiben
      if (serverArtworks.length === 0 && localArtworks.length > 0) {
        setIsLoadingFromServer(false)
        setSyncStatusBar({ phase: 'error', message: 'Server lieferte 0 Werke.' })
        if (!silent) setTimeout(() => {
          alert('Server hat keine Werke geliefert. Deine lokalen Daten (' + localArtworks.length + ' Werke) bleiben unverändert.\n\nZuerst am anderen Gerät „An Server senden“ tippen, dann hier erneut „Aktuellen Stand holen“.')
        }, 0)
        return
      }
      if (serverArtworks.length < localArtworks.length * 0.5 && localArtworks.length > 0) {
        setIsLoadingFromServer(false)
        setSyncStatusBar({ phase: 'error', message: 'Server-Stand viel kleiner als lokal.' })
        if (!silent) setTimeout(() => {
          alert('Server: ' + serverArtworks.length + ' Werke, lokal: ' + localArtworks.length + '. Zu großer Unterschied – Sync übersprungen. Deine lokalen Daten bleiben erhalten.\n\nWenn du wirklich nur den Server-Stand willst: Einstellungen → „Werke vom Server zurückholen“.')
        }, 0)
        return
      }
      // iPad/Mobil: Du hast mehr Werke als der Server → niemals überschreiben (Bilder würden verloren gehen). Zuerst hier „An Server senden“.
      if (isMobileDevice && localArtworks.length > serverArtworks.length) {
        setIsLoadingFromServer(false)
        setSyncStatusBar({ phase: 'error', message: 'Lokal mehr Werke als Server.' })
        if (!silent) setTimeout(() => {
          alert(
            'Du hast mehr Werke (' + localArtworks.length + ') als der Server (' + serverArtworks.length + ').\n\n' +
            'Damit deine Bilder nicht verloren gehen: Zuerst hier „An Server senden“ tippen. Danach am anderen Gerät „Aktuellen Stand holen“.'
          )
        }, 0)
        return
      }
      // Ein Standard: dieselbe Merge-Logik wie GaleriePage (Key-Normalisierung 0030 ↔ K2-K-0030, preserveLocalImageData)
      const { merged: mergedWithImages } = applyServerDataToLocal(serverArtworks, localArtworks, {
        onlyAddLocalIfMobileAndVeryNew: true,
        serverAsSoleTruth: true,
      })
      // Zuerst fehlende Bild-URLs aus lokaler IndexedDB holen und hochladen (6 Werke 0030–0038, K2-M-0018), dann aus Supabase
      const withIndexedDB = await fillMissingImageUrlsFromIndexedDB(mergedWithImages)
      const withSupabaseImages = await fillArtworkImageUrlsFromSupabase(withIndexedDB)
      // Data-URLs vor strip in IndexedDB sichern → Kette stimmt, Karte bekommt das richtige Bild
      const afterPersist = await persistDataUrlsToIndexedDB(withSupabaseImages)
      const toSave = filterK2Only(stripBase64FromArtworks(afterPersist))
      // Nur echte Bild-URLs (https) zählen – imageRef allein lädt auf iPad oft nicht (IndexedDB leer)
      const hasImageUrl = (a: any) => a?.imageUrl && typeof a.imageUrl === 'string' && (a.imageUrl.startsWith('http://') || a.imageUrl.startsWith('https://'))
      const savedWithImageCount = toSave.filter(hasImageUrl).length
      const withoutImageNumbers = toSave.filter((a: any) => !hasImageUrl(a)).map((a: any) => String(a?.number ?? a?.id ?? '').trim()).filter(Boolean)
      const localWithImageCount = localArtworks.filter(
        (a: any) =>
          (a?.imageUrl && typeof a.imageUrl === 'string' && (a.imageUrl.startsWith('http://') || a.imageUrl.startsWith('https://'))) ||
          (a?.imageRef && typeof a.imageRef === 'string' && a.imageRef.trim() !== '')
      ).length
      // Bildverlust: Lokal mehr Werke mit Bild als der Server/Merge liefern würde
      if (savedWithImageCount < localWithImageCount && localWithImageCount > 0) {
        if (silent) {
          setIsLoadingFromServer(false)
          setSyncStatusBar({ phase: 'idle', message: '' })
          return
        }
        const hintFrisch =
          'Falls du gerade vom anderen Gerät (z. B. iPad) gesendet hast: 1–2 Min warten und erneut „Aktuellen Stand holen“ – der Server braucht manchmal einen Moment, dann kommt der neue Stand (z. B. 70 Werke, 10 mit Bild) an.'
        // iPad/Mobil: Frage wie am Mac – „Trotzdem laden“ möglich, damit er nicht blockiert ist.
        if (isMobileDevice) {
          const ok = window.confirm(
            'Lokal haben ' + localWithImageCount + ' Werke ein Bild, der Server liefert nur ' + savedWithImageCount + '.\n\n' +
            hintFrisch + '\n\n' +
            'Oder jetzt Server-Stand übernehmen? („Trotzdem laden“ – lokale Daten werden ersetzt.)'
          )
          if (!ok) {
            setIsLoadingFromServer(false)
            setSyncStatusBar({ phase: 'idle', message: '' })
            return
          }
        } else {
          const ok = window.confirm(
            `Achtung – möglicher Bildverlust:\n\nLokal haben ${localWithImageCount} Werke ein Bild. Nach dem Laden vom Server wären es nur ${savedWithImageCount} mit abrufbarer Bild-URL.\n\n${hintFrisch}\n\nTrotzdem jetzt laden? (Lokale Daten werden ersetzt.)`
          )
          if (!ok) {
            setIsLoadingFromServer(false)
            setSyncStatusBar({ phase: 'success', message: 'Abgebrochen.' })
            setTimeout(() => alert('Abgebrochen. Deine lokalen Daten (inkl. Bilder) bleiben unverändert.'), 0)
            return
          }
        }
      }
      if (toSave.length >= localArtworks.length || toSave.length >= (loadArtworks(tenant).length || 0)) {
        const saved = await saveArtworks(tenant, toSave)
        if (saved) {
          const resolved = await loadArtworksWithResolvedImages(tenant)
          setAllArtworksSafe(resolved)
          window.dispatchEvent(new CustomEvent('artworks-updated', { detail: { count: toSave.length, fromLocalWrite: true } }))
          setIsLoadingFromServer(false)
          const loadedAt = data.exportedAt || new Date().toISOString()
          try { localStorage.setItem('k2-last-loaded-timestamp', loadedAt) } catch (_) {}
          setLastSyncLoadedAt(loadedAt)
          const exportedAt = data.exportedAt ? ` (Stand: ${new Date(data.exportedAt).toLocaleString('de-AT', { dateStyle: 'short', timeStyle: 'short' })})` : ''
          if (silent) {
            setSyncStatusBar({ phase: 'success', message: 'Daten vom Server geladen.' })
            setTimeout(() => { if (isMountedRef.current) setSyncStatusBar((p) => (p.message?.includes('Daten vom Server geladen') ? { phase: 'idle', message: '' } : p)) }, 4000)
          } else {
            setSyncStatusBar({ phase: 'loading', message: `${toSave.length} Werke geladen. Bilder werden angezeigt…` })
            setTimeout(() => {
              setSyncStatusBar({ phase: 'success', message: 'Geladen.' })
              const ohneBildHinweis = withoutImageNumbers.length > 0 ? `\n\nOhne Bild-URL: ${withoutImageNumbers.slice(0, 15).join(', ')}${withoutImageNumbers.length > 15 ? ' …' : ''}` : ''
              alert(`✅ ${toSave.length} Werke vom Server geladen${exportedAt}.\n\nGespeichert: ${toSave.length} Werke, ${savedWithImageCount} mit Bild-URL (so viele siehst du in der Galerie).${ohneBildHinweis}`)
            }, 4000)
          }
        } else {
          setSyncStatusBar({ phase: 'error', message: 'Fehler beim Speichern.' })
        }
      } else {
        console.warn('Merge würde weniger Werke ergeben – localStorage unverändert')
        const serverCount = serverArtworks.length
        const localCount = localArtworks.length
        if (silent) {
          setIsLoadingFromServer(false)
          setSyncStatusBar({ phase: 'idle', message: '' })
          return
        }
        const nurServerLaden = window.confirm(
          `Server hat ${serverCount} Werke, lokal ${localCount}.\n\nNur den Server-Stand (${serverCount} Werke) laden? Lokale Werke werden ersetzt.`
        )
        if (nurServerLaden) {
          const preserved = preserveLocalImageData(serverArtworks, localArtworks, (a: any) => String(a?.number ?? a?.id ?? ''))
          const withIndexedDB = await fillMissingImageUrlsFromIndexedDB(preserved)
          const withSupabaseImages = await fillArtworkImageUrlsFromSupabase(withIndexedDB)
          const afterPersist = await persistDataUrlsToIndexedDB(withSupabaseImages)
          const toSaveOnly = stripBase64FromArtworks(afterPersist)
          const hasImg = (a: any) => a?.imageUrl && typeof a.imageUrl === 'string' && (a.imageUrl.startsWith('http://') || a.imageUrl.startsWith('https://'))
          const savedWithImageOnly = toSaveOnly.filter(hasImg).length
          const withoutImageOnly = toSaveOnly.filter((a: any) => !hasImg(a)).map((a: any) => String(a?.number ?? a?.id ?? '').trim()).filter(Boolean)
          const saved = await saveArtworks(tenant, filterK2Only(toSaveOnly))
          if (saved) {
            const resolved = await loadArtworksWithResolvedImages(tenant)
            setAllArtworksSafe(resolved)
            window.dispatchEvent(new CustomEvent('artworks-updated', { detail: { count: serverCount, fromLocalWrite: true } }))
            const loadedAt = data.exportedAt || new Date().toISOString()
            try { localStorage.setItem('k2-last-loaded-timestamp', loadedAt) } catch (_) {}
            setLastSyncLoadedAt(loadedAt)
            setSyncStatusBar({ phase: 'loading', message: `${serverCount} Werke geladen. Bilder werden angezeigt…` })
            setTimeout(() => {
              setSyncStatusBar({ phase: 'success', message: 'Geladen.' })
              const ohneHinweis = withoutImageOnly.length > 0 ? `\n\nOhne Bild-URL: ${withoutImageOnly.slice(0, 15).join(', ')}${withoutImageOnly.length > 15 ? ' …' : ''}` : ''
              alert(`✅ ${serverCount} Werke vom Server geladen (nur Server-Stand).\n\nGespeichert: ${serverCount} Werke, ${savedWithImageOnly} mit Bild-URL (so viele siehst du in der Galerie).${ohneHinweis}`)
            }, 4000)
          } else {
            setSyncStatusBar({ phase: 'error', message: 'Fehler beim Speichern.' })
          }
        } else {
          setSyncStatusBar({ phase: 'success', message: 'Lokal beibehalten.' })
          if (!silent) setTimeout(() => { alert('Lokal beibehalten. Für nur Server-Stand: Einstellungen → „Werke vom Server zurückholen“.') }, 0)
        }
        setIsLoadingFromServer(false)
      }
    } catch (e) {
      console.error('Vom Server laden:', urlPrimary, e)
      setSyncStatusBar({ phase: 'error', message: 'Fehler beim Laden.' })
      if (!silent) {
        const msg = e instanceof Error ? e.message : String(e)
        const isNetwork = /failed|network|load|cors|fetch|typeerror/i.test(msg) || (e instanceof TypeError)
        alert(
          isNetwork
            ? 'Verbindung zum Server fehlgeschlagen.\n\n• Bist du im Internet? (WLAN oder Mobil)\n• App von k2-galerie.vercel.app geöffnet? Dann erneut „Bilder vom Server laden“ klicken.'
            : `Fehler beim Laden: ${msg}\n\nBitte Verbindung prüfen und erneut versuchen.`
        )
      }
    } finally {
      setIsLoadingFromServer(false)
    }
  }

  // REGEL: Nach jedem Neuladen des Geräts (Seite/Admin geöffnet) automatisch Daten vom Vercel-Server holen – keine manuelle Eingabe nötig. Einmal pro Mount, nur K2, still (kein Alert).
  useEffect(() => {
    if (tenant.isOeffentlich || tenant.isVk2 || tenant.dynamicTenantId) return
    if (hasAutoLoadedFromServerRef.current) return
    hasAutoLoadedFromServerRef.current = true
    const t = setTimeout(() => {
      handleLoadFromServer({ silent: true })
    }, 1500)
    return () => clearTimeout(t)
  }, [tenant.isOeffentlich, tenant.isVk2, tenant.dynamicTenantId])

  /** K2: Werke aus der veröffentlichten gallery-data.json (Vercel) laden und in k2-artworks wiederherstellen. Server-Stand als Basis, lokale Bilddaten (imageUrl/imageRef) werden erhalten – keine Überschreibung mit leeren Bildern (z. B. 30–48). */
  const handleRestoreWerkeFromPublished = async () => {
    if (tenant.isOeffentlich || tenant.isVk2) return
    setIsRestoringWerkeFromPublished(true)
    const urlPrimary = `${CENTRAL_GALLERY_DATA_URL}?v=${Date.now()}&_=${Math.random()}`
    const urlFallback = `${CENTRAL_GALLERY_DATA_FALLBACK_URL}?v=${Date.now()}&_=${Math.random()}`
    const LOAD_TIMEOUT_MS = 60000 // 60 s – 70 Werke können etwas dauern
    try {
      const controller = new AbortController()
      const timeoutId = setTimeout(() => controller.abort(), LOAD_TIMEOUT_MS)
      let res: Response
      try {
        res = await fetch(urlPrimary, { cache: 'no-store', signal: controller.signal })
      } catch (err) {
        clearTimeout(timeoutId)
        if (err instanceof Error && err.name === 'AbortError') {
          throw new Error('Zeitüberschreitung (60 s). Server antwortet nicht – Internet/Vercel prüfen.')
        }
        throw err
      }
      if (!res.ok) {
        res = await fetch(urlFallback, { cache: 'no-store', signal: controller.signal })
      }
      clearTimeout(timeoutId)
      if (!res.ok) throw new Error(`HTTP ${res.status}`)
      const data = await res.json()
      const serverList = filterK2Only(Array.isArray(data?.artworks) ? data.artworks : [])
      if (serverList.length === 0) {
        alert('Auf dem Server liegt noch kein Stand deiner Werke.\n\nKlicke zuerst einmal auf „An Server senden“, damit deine Werke dorthin gespeichert werden. Oder nutze „Aus Backup-Datei wiederherstellen“.')
        return
      }
      const localArtworks = loadArtworksRaw(tenant)
      const getKey = (a: any) => String(a?.number ?? a?.id ?? '')
      const withPreservedImages = preserveLocalImageData(serverList, localArtworks, getKey)
      const withIndexedDB = await fillMissingImageUrlsFromIndexedDB(withPreservedImages)
      const withSupabaseImages = await fillArtworkImageUrlsFromSupabase(withIndexedDB)
      const afterPersist = await persistDataUrlsToIndexedDB(withSupabaseImages)
      const toSave = stripBase64FromArtworks(afterPersist)
      const ok = await saveArtworksByKeyWithImageStore('k2-artworks', toSave, { filterK2Only: true, allowReduce: true })
      if (!ok) {
        alert('Die Daten konnten nicht gespeichert werden (z. B. Speicher voll). Bitte „Speicher entlasten“ oder „Aus Backup-Datei wiederherstellen“ nutzen.')
        return
      }
      const resolved = await loadArtworksWithResolvedImages(tenant)
      setAllArtworksSafe(resolved)
      if (typeof window !== 'undefined') window.dispatchEvent(new CustomEvent('artworks-updated', { detail: { fromLocalWrite: true } }))
      try { localStorage.setItem('k2-last-loaded-timestamp', data.exportedAt || new Date().toISOString()) } catch (_) {}
      setLastSyncLoadedAt(data.exportedAt || new Date().toISOString())
      alert(`✅ Fertig. ${toSave.length} Werke wurden vom Server geladen (lokale Bilder beibehalten).`)
    } catch (e) {
      console.error('Werke aus Veröffentlichung wiederherstellen:', e)
      const msg = e instanceof Error ? e.message : String(e)
      const isNetwork = /failed|network|load|cors|fetch|typeerror|zeitüberschreitung|abort/i.test(msg) || (e instanceof TypeError)
      alert(
        isNetwork
          ? 'Verbindung zum Server fehlgeschlagen oder Zeitüberschreitung.\n\n• Bist du im Internet? (WLAN/Mobil)\n• App von k2-galerie.vercel.app öffnen und erneut „Werke vom Server zurückholen“ klicken.'
          : `Fehler: ${msg}\n\nBitte Verbindung prüfen und erneut versuchen.`
      )
    } finally {
      setIsRestoringWerkeFromPublished(false)
    }
  }

  // Dokumente aus localStorage laden (Key abhängig von K2 vs. ök2). ök2: 5 fertige Muster-PR-Dokumente (Newsletter, Plakat, Flyer, Presse, Social) + Event-Docs aus MUSTER_EVENTS = 7 Muster.
  const loadDocuments = () => {
    try {
      // ök2: Muster-Dokumente + Einträge aus localStorage mergen (sonst verschwinden neu erzeugte PR-Dokumente nach Reload)
      if (tenant.isOeffentlich) {
        const muster = getOek2MusterPrDocuments()
        const stored = loadDocumentsFromStorage('oeffentlich')
        if (!Array.isArray(stored) || stored.length === 0) return muster
        const musterIds = new Set(muster.map((d: { id: string }) => d.id))
        const mergedMuster = muster.map((d: Record<string, unknown>) => {
          const s = stored.find((x: { id?: string }) => x.id === d.id)
          return s ? { ...d, ...s } : d
        })
        const extras = stored.filter((x: { id?: string }) => x.id && !musterIds.has(x.id))
        return [...mergedMuster, ...extras]
      }
      if (tenant.isVk2) initVk2DemoEventAndDocumentsIfEmpty()
      const stored = localStorage.getItem(tenant.getDocumentsKey())
      if (stored) return JSON.parse(stored)
      return []
    } catch (error) {
      console.error('Fehler beim Laden der Dokumente:', error)
      return []
    }
  }

  // Eindeutiger Name für weiteren Werbematerial-Vorschlag (mehrere pro Zeile)
  const getNextWerbematerialVorschlagName = (
    eventId: string,
    eventTitle: string,
    werbematerialTyp: string,
    baseName: string
  ): string => {
    const eventIdNorm = eventId != null ? String(eventId) : ''
    const existing = loadDocuments().filter(
      (d: any) => d.category === 'pr-dokumente' && d.eventId != null && String(d.eventId) === eventIdNorm && d.werbematerialTyp === werbematerialTyp
    )
    const num = existing.length + 1
    return num === 1 ? `${baseName} – ${eventTitle}` : `${baseName} – ${eventTitle} (Vorschlag ${num})`
  }

  // Dokumente aus localStorage laden – bei Kontextwechsel sofort (0 ms), damit richtiger Key/Kontext vor jedem Speichern gilt
  useEffect(() => {
    if (tenant.dynamicTenantId) return
    let isMounted = true
    try {
      const docs = loadDocuments()
      if (isMounted) setDocuments(docs)
    } catch (error) {
      console.error('Fehler beim Laden der Dokumente:', error)
      if (isMounted) setDocuments([])
    }
    return () => { isMounted = false }
  }, [location.search])

  // Speichern aus geöffnetem Social-Media-Dokument (postMessage vom Kind-Fenster)
  useEffect(() => {
    const handler = (e: MessageEvent) => {
      if (e.origin !== window.location.origin || e.data?.type !== 'k2-save-social-doc') return
      const payload = e.data.payload
      if (!payload?.docId) return
      try {
        const docs = loadDocuments()
        const idx = docs.findIndex((d: any) => d.id === payload.docId)
        if (idx < 0) return
        const isVk2 = tenant.isVk2
        const prDocClass = isVk2 ? 'vk2-pr-doc' : 'k2-pr-doc'
        const prDocCss = isVk2 ? getWerbeliniePrDocCssVk2('vk2-pr-doc') : getPlakatDesignPrDocCss('k2-pr-doc', designSettings)
        const galleryName = (() => {
          if (isVk2) return vk2Stammdaten?.verein?.name || 'Kunstverein Muster'
          const g = galleryData || {}
          return g.name || (tenant.isOeffentlich ? TENANT_CONFIGS.oeffentlich.galleryName : 'K2 Galerie')
        })()
        const html = buildSocialMediaEditableHtml({
          socialMedia: {
            instagram: payload.instagram ?? '',
            facebook: payload.facebook ?? '',
            whatsapp: payload.whatsapp ?? ''
          },
          eventLike: { title: payload.eventTitle ?? '', date: payload.eventDate },
          imageDataUrl: payload.imageDataUrl || undefined,
          options: {
            socialDocId: payload.docId,
            adminReturnUrl: getAdminReturnUrl(activeTab, eventplanSubTab),
            prDocClass,
            prDocCss,
            galleryName
          }
        })
        const blob = new Blob([html], { type: 'text/html;charset=utf-8' })
        const reader = new FileReader()
        reader.onloadend = () => {
          const current = loadDocuments()
          const updated = current.map((d: any) => d.id === payload.docId ? { ...d, fileData: reader.result as string, data: reader.result as string } : d)
          saveDocuments(updated)
          setDocuments(updated)
        }
        reader.readAsDataURL(blob)
      } catch (err) {
        console.error('Fehler beim Speichern des Social-Media-Dokuments:', err)
      }
    }
    window.addEventListener('message', handler)
    return () => window.removeEventListener('message', handler)
  }, [activeTab, eventplanSubTab, tenant.dynamicTenantId, designSettings, galleryData, vk2Stammdaten])

  // Speichern aus geöffnetem Presse/Plakat/Flyer-Fenster (postMessage mit HTML)
  useEffect(() => {
    const handler = (e: MessageEvent) => {
      if (e.origin !== window.location.origin || e.data?.type !== 'k2-save-doc-html') return
      const payload = e.data.payload
      if (!payload?.docId || typeof payload?.html !== 'string') return
      try {
        const blob = new Blob([payload.html], { type: 'text/html;charset=utf-8' })
        const reader = new FileReader()
        reader.onloadend = () => {
          const current = loadDocuments()
          const updated = current.map((d: any) => d.id === payload.docId ? { ...d, fileData: reader.result as string, data: reader.result as string } : d)
          saveDocuments(updated)
          setDocuments(updated)
          setDocumentSaveFeedback('ok')
          setTimeout(() => setDocumentSaveFeedback(null), 3000)
        }
        reader.readAsDataURL(blob)
      } catch (err) {
        console.error('Fehler beim Speichern des Dokuments (k2-save-doc-html):', err)
      }
    }
    window.addEventListener('message', handler)
    return () => window.removeEventListener('message', handler)
  }, [])

  // Events aus localStorage laden – bei Kontextwechsel SOFORT (0 ms), damit Auto-Save nie mit VK2-State in K2 schreibt
  useEffect(() => {
    if (tenant.dynamicTenantId) return
    let isMounted = true
    try {
      const loadedEvents = loadEvents(tenant)
      if (isMounted) setEvents(loadedEvents)
    } catch (error) {
      console.error('Fehler beim Laden der Events:', error)
      if (isMounted) setEvents([])
    }
    return () => { isMounted = false }
  }, [location.search])
  
  // AUTO-SAVE: Speichere alle Daten automatisch alle 5 Sekunden - VERHINDERT DATENVERLUST BEI CRASHES
  useEffect(() => {
    let isMounted = true
    
    // Funktion die alle Daten sammelt – in iframe allArtworks ist „leicht“ (ohne Base64), Auto-Save braucht volle Daten aus localStorage
    const getAllData = () => ({
      martina: martinaData,
      georg: georgData,
      gallery: galleryData,
      artworks: (typeof window !== 'undefined' && window.self !== window.top) ? loadArtworks(tenant) : allArtworks,
      events: events,
      documents: documents,
      designSettings: designSettings,
      pageTexts: pageTexts
    })
    
    // KRITISCH: Auto-Save nur in K2 – in ök2/VK2 niemals in K2-Keys schreiben (Datenquelle eine pro Kontext).
    // Wenn Auto-Save bei VK2 liefe, würde VK2-State (pageTexts, Stammdaten) in k2-page-texts / k2-stammdaten-* landen → K2-Galerie zeigt VK2-Inhalte.
    // Zweite Absicherung: URL direkt prüfen (case-insensitive), falls tenant aus sessionStorage/Reihenfolge mal falsch wäre.
    const search = typeof location !== 'undefined' ? (location.search || '').toLowerCase() : ''
    const urlSaysOeffentlich = search.includes('context=oeffentlich')
    const urlSaysVk2 = search.includes('context=vk2')
    if (tenant.dynamicTenantId) {
      // Kein Auto-Save – Speichern nur über „Veröffentlichen“ → write-gallery-data
    } else if (!tenant.isOeffentlich && !tenant.isVk2 && !urlSaysOeffentlich && !urlSaysVk2) {
      startAutoSave(getAllData)
      setupBeforeUnloadSave(getAllData)
    }
    
    return () => {
      isMounted = false
      stopAutoSave()
    }
  }, [tenant.tenantId, tenant.isOeffentlich, tenant.isVk2, martinaData, georgData, galleryData, allArtworks, events, documents, designSettings, pageTexts])

  // Event hinzufügen/bearbeiten
  const handleSaveEvent = () => {
    if (!eventTitle || !eventDate) {
      alert('Bitte Titel und Datum eingeben')
      return
    }

    const eventData = {
      id: editingEvent?.id || `event-${Date.now()}`,
      title: eventTitle,
      type: eventType,
      date: eventDate,
      endDate: eventEndDate || eventDate, // Falls kein Enddatum, dann Startdatum verwenden
      startTime: eventStartTime || '',
      endTime: eventEndTime || '',
      dailyTimes: eventDailyTimes || {}, // Tägliche Zeiten für jeden Tag
      description: eventDescription,
      location: eventLocation,
      documents: editingEvent?.documents || [],
      createdAt: editingEvent?.createdAt || new Date().toISOString(),
      updatedAt: new Date().toISOString()
    }

    let updatedEvents
    if (editingEvent) {
      updatedEvents = events.map(e => e.id === editingEvent.id ? eventData : e)
    } else {
      updatedEvents = [...events, eventData]
    }

    // Nach Startdatum sortieren
    updatedEvents.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())

    setEvents(updatedEvents)
    saveEvents(tenant, updatedEvents)
    try {
      window.dispatchEvent(new CustomEvent('k2-events-updated'))
    } catch {
      /* ignore */
    }

    // PR-Vorschläge: Bei Bearbeitung eventTitle in localStorage aktualisieren; bei neuem Event automatisch generieren
    const existingSuggestions = JSON.parse(localStorage.getItem('k2-pr-suggestions') || '[]')
    const suggestionIndex = existingSuggestions.findIndex((s: any) => s.eventId === eventData.id)
    if (editingEvent && suggestionIndex >= 0) {
      existingSuggestions[suggestionIndex].eventTitle = eventData.title
      existingSuggestions[suggestionIndex].eventId = eventData.id
      localStorage.setItem('k2-pr-suggestions', JSON.stringify(existingSuggestions))
    } else if (!editingEvent) {
      generateAutomaticSuggestions(eventData)
    }
    
    // Zurücksetzen
    setShowEventModal(false)
    setEditingEvent(null)
    setEventTitle('')
    setEventType('galerieeröffnung')
    setEventDate('')
    setEventEndDate('')
    setEventStartTime('')
    setEventEndTime('')
    setEventDailyTimes({})
    setEventDescription('')
    setEventLocation('')
    
    if (editingEvent) {
      alert('✅ Event aktualisiert!')
    } else {
      setEventplanSubTab('öffentlichkeitsarbeit')
      alert('✅ Event angelegt. Unten siehst du die neue Rubrik mit allen Werbe-Werkzeugen – Newsletter, Presse, Social Media, PDF.')
    }
  }

  // Event bearbeiten
  const handleEditEvent = (event: any) => {
    setEditingEvent(event)
    setEventTitle(event.title)
    setEventType(event.type)
    setEventDate(event.date)
    setEventEndDate(event.endDate || event.date)
    setEventStartTime(event.startTime || event.time || '')
    setEventEndTime(event.endTime || '')
    // Konvertiere alte Format (string) zu neuem Format (object mit start/end)
    const dailyTimes = event.dailyTimes || {}
    const convertedDailyTimes: Record<string, { start: string, end: string }> = {}
    Object.keys(dailyTimes).forEach(day => {
      const time = dailyTimes[day]
      if (typeof time === 'string') {
        convertedDailyTimes[day] = { start: time, end: '' }
      } else {
        convertedDailyTimes[day] = { start: time?.start || '', end: time?.end || '' }
      }
    })
    setEventDailyTimes(convertedDailyTimes)
    setEventDescription(event.description || '')
    setEventLocation(event.location || '')
    setShowEventModal(true)
  }

  // Alle Tage zwischen Start- und Enddatum generieren
  const getEventDays = (startDate: string, endDate: string): string[] => {
    if (!startDate) return []
    const end = endDate || startDate
    const days: string[] = []
    const start = new Date(startDate)
    const endDateObj = new Date(end)
    
    for (let d = new Date(start); d <= endDateObj; d.setDate(d.getDate() + 1)) {
      days.push(d.toISOString().split('T')[0])
    }
    
    return days
  }

  /** Anmeldung per WhatsApp – Text zum Kopieren oder wa.me-Link („Komme Fr/Sa, So leider nicht“). */
  const getWhatsAppAnmeldungForEvent = (event: any): { text: string; waUrl: string | null } => {
    if (!event?.title) return { text: '', waUrl: null }
    const days = getEventDays(event.date || '', event.endDate || event.date || '')
    const dayLines = days.length > 0
      ? days.map((d: string) => {
          const dd = new Date(d)
          const label = dd.toLocaleDateString('de-DE', { weekday: 'short', day: 'numeric', month: 'numeric' })
          return `[ ] ${label}`
        })
      : [event.date ? `[ ] ${new Date(event.date).toLocaleDateString('de-DE', { weekday: 'short', day: 'numeric', month: 'long', year: 'numeric' })}` : '[ ] Datum']
    const text = [
      `${event.title} – Anmeldung`,
      '',
      'Ich komme:',
      ...dayLines,
      '[ ] Leider nicht',
      '',
      'Name: ___'
    ].join('\n')
    const rawPhone = (galleryData?.phone || martinaData?.phone || georgData?.phone || '').replace(/\s/g, '')
    const digits = rawPhone.replace(/\D/g, '')
    const normalized = digits.startsWith('0') ? '43' + digits.slice(1) : digits.length >= 9 ? (digits.startsWith('43') ? digits : '43' + digits) : ''
    const waUrl = normalized.length >= 10 ? `https://wa.me/${normalized}?text=${encodeURIComponent(text)}` : null
    return { text, waUrl }
  }

  // Automatische Vorschläge für neues Event generieren
  const generateAutomaticSuggestions = (event: any) => {
    // Speichere Vorschläge in localStorage
    const suggestions = {
      eventId: event.id,
      eventTitle: event.title,
      generatedAt: new Date().toISOString(),
      presseaussendung: generatePresseaussendungContent(event),
      socialMedia: generateSocialMediaContent(event),
      flyer: generateFlyerContent(event),
      newsletter: generateNewsletterContent(event),
      plakat: generatePlakatContent(event)
    }
    
    const existingSuggestions = JSON.parse(localStorage.getItem('k2-pr-suggestions') || '[]')
    existingSuggestions.push(suggestions)
    localStorage.setItem('k2-pr-suggestions', JSON.stringify(existingSuggestions))
  }

  /** Presseaussendung: Redaktions-Modal (Split-Ansicht). optionalOverride = z. B. frisch generiert neutral/lokal; sonst Vorschlag aus k2-pr-suggestions oder Standard. */
  const openRedaction = (event: any, optionalOverride?: any) => {
    const defaultQr = BASE_APP_URL + (tenant.isVk2 ? PROJECT_ROUTES.vk2.galerie : tenant.isOeffentlich ? PROJECT_ROUTES['k2-galerie'].galerieOeffentlich : PROJECT_ROUTES['k2-galerie'].galerie)
    try {
      const raw = localStorage.getItem('k2-pr-suggestions') || '[]'
      const list = JSON.parse(raw)
      const sug = list.find((s: any) => s.eventId === event.id)
      const presse = optionalOverride ?? sug?.presseaussendung ?? generatePresseaussendungContent(event)
      setRedactionPresseTitle(presse?.title ?? '')
      setRedactionPresseContent(presse?.content ?? '')
      setRedactionPresseImageUrl(presse?.imageUrl ?? '')
      setRedactionPresseQrShow(!!presse?.qrShow)
      setRedactionPresseQrUrl(presse?.qrUrl ?? defaultQr)
      setRedactionEvent(event)
    } catch {
      setRedactionPresseTitle('')
      setRedactionPresseContent('')
      setRedactionPresseImageUrl('')
      setRedactionPresseQrShow(false)
      setRedactionPresseQrUrl(defaultQr)
      setRedactionEvent(event)
    }
  }

  /** Social-Media-Redaktion öffnen (zweigeteilte Ansicht: links bearbeiten, rechts Vorschau). eventLike = Event oder { id, title, date }; doc = bestehendes Dokument oder null. */
  const openSocialRedaction = (eventLike: any, doc: any, socialContent: { instagram?: string; facebook?: string; whatsapp?: string; imageDataUrl?: string }) => {
    setSocialRedactionEvent(eventLike)
    setSocialRedactionDocument(doc ?? null)
    setSocialRedactionInstagram(socialContent?.instagram ?? '')
    setSocialRedactionFacebook(socialContent?.facebook ?? '')
    setSocialRedactionWhatsApp(socialContent?.whatsapp ?? '')
    setSocialRedactionImageUrl(socialContent?.imageDataUrl ?? '')
  }

  /** Newsletter-Redaktion öffnen (zweigeteilte Ansicht). Bei Eröffnung immer frischen Inhalt (starker Text, Termine aus Event). */
  const openNewsletterRedaction = (eventLike: any, doc: any, content: { subject?: string; body?: string }) => {
    setNewsletterRedactionEvent(eventLike)
    setNewsletterRedactionDocument(doc ?? null)
    const useContent = eventLike?.type === 'galerieeröffnung'
      ? generateNewsletterContent(eventLike)
      : content
    setNewsletterRedactionSubject(useContent?.subject ?? '')
    setNewsletterRedactionBody(useContent?.body ?? '')
  }

  /** Plakat-Redaktion: wie Newsletter, links Felder, rechts Vorschau mit Format-Leiste */
  const openPlakatRedaction = (event: any) => {
    if (!event) return
    setPlakatRedactionEvent(event)
    setPlakatRedactionDoc(null)
    const freshGalleryData = (() => {
      if (tenant.isOeffentlich) return galleryData || {}
      if (tenant.isVk2) {
        const v = vk2Stammdaten?.verein
        return v ? { name: v.name, address: v.address, city: v.city, website: v.website || '', phone: (v as any).phone || '', email: v.email || '' } : {}
      }
      return loadStammdaten('k2', 'gallery') as Record<string, unknown>
    })()
    const freshSuggestions = JSON.parse(localStorage.getItem('k2-pr-suggestions') || '[]')
    const freshEventSuggestion = freshSuggestions.find((s: any) => s.eventId === event.id)
    let plakatContent: any = freshEventSuggestion?.plakat || generatePlakatContent(event)
    if (!plakatContent || typeof plakatContent !== 'object') plakatContent = generatePlakatContent(event)
    plakatContent.title = event.title || plakatContent.title || 'Event'
    plakatContent.date = formatEventDates(event) || plakatContent.date || 'Datum folgt'
    plakatContent.location = event.location || plakatContent.location || (freshGalleryData as any).address || ''
    plakatContent.description = event.description || plakatContent.description || ''
    const websiteUrl = ((freshGalleryData as any).website && isProductionLikeUrl((freshGalleryData as any).website))
      ? (freshGalleryData as any).website
      : FALLBACK_GALERIE_URL_WERBEMITTEL
    plakatContent.qrCode = websiteUrl
    const eventTypeNames: Record<string, string> = {
      galerieeröffnung: 'Galerieeröffnung',
      vernissage: 'Vernissage',
      finissage: 'Finissage',
      öffentlichkeitsarbeit: 'Öffentlichkeitsarbeit',
      sonstiges: 'Veranstaltung'
    }
    plakatContent.type = eventTypeNames[event.type] || plakatContent.type || 'Veranstaltung'
    setPlakatRedaction({
      title: String(plakatContent.title || ''),
      type: String(plakatContent.type || ''),
      date: String(plakatContent.date || ''),
      location: String(plakatContent.location || ''),
      description: String(plakatContent.description || ''),
      qrCode: String(plakatContent.qrCode || websiteUrl)
    })
  }

  /** Flyer-Redaktion: wie Newsletter */
  const openFlyerRedaction = (event: any) => {
    if (!event) return
    setFlyerRedactionEvent(event)
    setFlyerRedactionDoc(null)
    const suggestions = JSON.parse(localStorage.getItem('k2-pr-suggestions') || '[]')
    const eventSuggestion = suggestions.find((s: any) => s.eventId === event.id)
    const flyerContent = eventSuggestion?.flyer || generateFlyerContent(event)
    setFlyerRedaction({
      headline: String(flyerContent.headline || event.title || ''),
      date: String(flyerContent.date || formatEventDates(event) || ''),
      location: String(flyerContent.location || ''),
      description: String(flyerContent.description || ''),
      type: String(flyerContent.type || event.type || ''),
      qrCode: String(flyerContent.qrCode || ''),
      contact: {
        phone: flyerContent.contact?.phone,
        email: flyerContent.contact?.email,
        address: flyerContent.contact?.address
      }
    })
  }

  // QR-Vorschau für Redaktions-Modal generieren, wenn QR aktiv und URL gesetzt
  React.useEffect(() => {
    if (!redactionEvent || !redactionPresseQrShow || !redactionPresseQrUrl) {
      setRedactionPresseQrDataUrl('')
      return
    }
    let cancelled = false
    QRCode.toDataURL(redactionPresseQrUrl, { width: 120, margin: 1 })
      .then((dataUrl) => { if (!cancelled) setRedactionPresseQrDataUrl(dataUrl) })
      .catch(() => { if (!cancelled) setRedactionPresseQrDataUrl('') })
    return () => { cancelled = true }
  }, [redactionEvent, redactionPresseQrShow, redactionPresseQrUrl])

  // Hilfsfunktion: Alle Termindaten formatieren
  const formatEventDates = (event: any): string => {
    if (!event || !event.date) {
      return 'Datum folgt'
    }
    try {
      const startDate = new Date(event.date)
      if (isNaN(startDate.getTime())) {
        return 'Datum folgt'
      }
      let endDate = event.endDate ? new Date(event.endDate) : null
      if (endDate && isNaN(endDate.getTime())) {
        // EndDate ist ungültig, ignoriere es
        endDate = null
      }
    
    let dateStr = startDate.toLocaleDateString('de-DE', {
      weekday: 'long',
      day: 'numeric',
      month: 'long',
      year: 'numeric'
    })
    
    if (endDate && endDate.getTime() !== startDate.getTime()) {
      dateStr += ` - ${endDate.toLocaleDateString('de-DE', {
        day: 'numeric',
        month: 'long',
        year: 'numeric'
      })}`
    }
    
    // Zeiten hinzufügen
    if (event.dailyTimes && Object.keys(event.dailyTimes).length > 0) {
      // Mehrteiliges Event mit täglichen Zeiten
      const times: string[] = []
      const days = getEventDays(event.date, event.endDate || event.date)
      days.forEach(day => {
        const dayTime = event.dailyTimes[day]
        if (dayTime) {
          const dayDate = new Date(day)
          if (typeof dayTime === 'string') {
            // Altes Format (nur Startzeit)
            times.push(`${dayDate.toLocaleDateString('de-DE', { weekday: 'short', day: 'numeric', month: 'short' })}: ${dayTime}`)
          } else if (dayTime.start || dayTime.end) {
            // Neues Format (Start- und Endzeit)
            const timeStr = dayTime.start 
              ? (dayTime.end ? `${dayTime.start} - ${dayTime.end} Uhr` : `${dayTime.start} Uhr`)
              : (dayTime.end ? `bis ${dayTime.end} Uhr` : '')
            if (timeStr) {
              times.push(`${dayDate.toLocaleDateString('de-DE', { weekday: 'short', day: 'numeric', month: 'short' })}: ${timeStr}`)
            }
          }
        }
      })
      if (times.length > 0) {
        dateStr += '\n\nZeiten:\n' + times.join('\n')
      }
    } else if (event.startTime) {
      dateStr += `\n🕐 ${event.startTime}${event.endTime ? ` - ${event.endTime}` : ''} Uhr`
    }
    
    return dateStr
    } catch (error) {
      console.error('Fehler beim Formatieren der Event-Daten:', error)
      return 'Datum folgt'
    }
  }

  // Beide Ausgangsgeschichten aus mök2 (MEDIENSTUDIO-K2 §1a / §1b) – für Presseaussendung
  const STORY_1A_HUMAN_PRESSE =
    'Die K2 Kunst Galerie betreiben Martina und Georg Kreinecker gemeinsam – Malerei und Keramik, nah an den Menschen. Die Plattform (ök2, VK2) hat Georg gebaut: Wer jahrzehntelang Maschinenbau und Vertrieb gemanagt hat, hat gewisse Ansprüche. An die Kassa. An die Organisation. An Marketing und Presse. Am Markt fand er vor allem Stückwerke – also wurde selbst gebaut. Heute heißt das Ergebnis K2 Galerie – Galerie, Kasse, Events und Presse aus einer Hand, und die Plattform wächst mit (ök2 für den gesamten Markt, Kunstmarkt = Einstieg; VK2 für alle Vereine, Kunstvereine = Einstieg). Kein Tech-Konzern, sondern einer, der nicht auf halben Lösungen sitzen bleiben wollte. Mit Augenzwinkern: Wer sein Leben lang Dinge organisiert hat, hört im Ruhestand nicht einfach auf.'
  const STORY_1B_PRODUKT_PRESSE =
    'Künstler:innen und kleine Galerien stehen vor demselben Problem: Sie brauchen Webauftritt, Kasse, Events und Presse – aber am Markt gibt es vor allem Stückwerke. Eine Software für die Galerie, eine andere für die Kasse, wieder eine für Einladungen. Die K2 Galerie ist aus genau dieser Lücke entstanden. Über Mein Weg wählen Nutzer:innen eine Sparte – von Kunst & Galerie über Handwerk, Design & Möbel, Mode, Food & Genuss bis Dienstleister & Portfolio. Daraus leiten sich Werktypen, Kategorien und die öffentliche Galerie-Logik ab; Corporate Design heißt: dieselbe visuelle Linie von Willkommen und Werken bis zu Flyer, Plakat und Presse – wiedererkennbar, aus einem Guss. Für große Anbieter ist dieser Markt zu klein; für Einzelne ist der Aufwand zu groß – genau dort positionieren wir uns: eine Oberfläche für alles. Galerie, Kasse, Events und Marketing aus einer Hand, ohne dass man sich durch ein Dutzend Programme klicken muss. Mittlerweile wächst die Plattform: ök2 für den gesamten Markt (Kunstmarkt = Einstieg), VK2 für alle Vereine (Kunstvereine = Einstieg) – alle Mitglieder, alle Werke, eine gemeinsame Galerie und eine Presse-Stimme. Keine Tech-Story von oben, sondern gebaut für die, die es brauchen.'

  // Eröffnung 24.–26.04. – Muster aus docs/MOK2-MUSTER-PRO-WERBETYP-EROEFFNUNG.md („Jetzt erstellen“ füllt Karte mit Strategie)
  // Phase 1: Erst Ausstellung Martina & Georg, zweitens Plattform (Lounge). Presse-Story (Lead + lokal) passt dazu.
  const EROEFFNUNG_KERNBOTSCHAFT =
    'Wir eröffnen die K2 Galerie – und laden Sie ein, die Galerie und die Plattform kennenzulernen, mit der wir und andere Künstler:innen, Galerien und Kunstvereine arbeiten.'
  const EROEFFNUNG_LOUNGE_TEXT =
    'Zur Eröffnung laden wir Sie herzlich ein: Erstens unsere Ausstellung – Werke von Martina und mir, Raum und Begegnung. Zweitens erleben Sie in unserer Lounge die K2-Plattform (K2 · ök2 · VK2) live – eine Oberfläche für Galerie, Kasse, Events und Presse aus einer Hand. Für Künstler:innen, Galerien und Kunstvereine, die sichtbar werden wollen.'
  const EROEFFNUNG_LOUNGE_TEXT_DU =
    'Zur Eröffnung laden wir dich herzlich ein: Erstens unsere Ausstellung – Werke von Martina und mir, Raum und Begegnung. Zweitens erlebst du in unserer Lounge die K2-Plattform (K2 · ök2 · VK2) live – eine Oberfläche für Galerie, Kasse, Events und Presse aus einer Hand. Für Künstler:innen, Galerien und Kunstvereine, die sichtbar werden wollen.'
  const EROEFFNUNG_LOUNGE_KURZ =
    'Ausstellung von Martina und mir – Werke, Raum, Begegnung. In unserer gemeinsamen Lounge: Einblick in K2 · ök2 · VK2.'
  const EROEFFNUNG_WERBELINIE_1 = 'K2 Galerie – für Künstler:innen, die gesehen werden wollen.'
  const EROEFFNUNG_WERBELINIE_2 = 'Deine Ideen, deine Werke verdienen mehr als einen Instagram-Post.'
  const EROEFFNUNG_WERBELINIE_2_SIE = 'Ihre Ideen, Ihre Werke verdienen mehr als einen Instagram-Post.'
  const EROEFFNUNG_PRESSE_LEAD_PREFIX = 'eröffnet am'
  const EROEFFNUNG_PLAKAT_KURZTEXT =
    'Kunst & Keramik · Ausstellung Martina & Georg\nGemeinsame Lounge: Plattform (K2 · ök2 · VK2) entdecken.'

  /** Bei jeder Information/Aussendung: Hinweis Link/QR → vorab K2, ök2, VK2 ansehen → konkrete Fragen beantworten. */
  const HINWEIS_LINK_QR_VORAB_SIE =
    'Hinweis: Über Link oder QR-Code können Sie sich vorab ein Bild von K2, ök2 und VK2 machen – dann können wir bei Ihrem Besuch konkrete Fragen beantworten.'
  const HINWEIS_LINK_QR_VORAB_DU =
    'Hinweis: Über Link oder QR-Code kannst du dir vorab ein Bild von K2, ök2 und VK2 machen – dann können wir bei deinem Besuch konkrete Fragen beantworten.'

  // Content-Generatoren im App-Design-Stil – je Kontext nur eigene Daten (K2 / ök2 / VK2)
  // variant: 'neutral' = ohne Personendaten/Kontakt (für neutrale Information), 'lokal' = mit Personenstory und Kontakt
  const generatePresseaussendungContent = (event: any, variant: 'neutral' | 'lokal' = 'lokal') => {
    const eventTypeLabels: Record<string, string> = {
      galerieeröffnung: 'Galerieeröffnung',
      vernissage: 'Vernissage',
      finissage: 'Finissage',
      öffentlichkeitsarbeit: 'Öffentlichkeitsarbeit',
      sonstiges: 'Veranstaltung'
    }
    const evType = eventTypeLabels[event.type] || 'Veranstaltung'
    const evDate = formatEventDates(event)

    if (tenant.isVk2) {
      const verein = vk2Stammdaten?.verein || { name: 'Kunstverein Muster', address: '', city: '', email: '', website: '' }
      const mitglieder = (vk2Stammdaten?.mitglieder || []).filter((m: any) => m?.name)
      const gName = verein.name || 'Kunstverein Muster'
      const adresse = [verein.address, verein.city].filter(Boolean).join(', ')
      const ort = event.location || adresse || ''
      const kuenstlerListe = mitglieder.length > 0 ? mitglieder.map((m: any) => m.name).join(', ') : 'die Vereinsmitglieder'
      const desc = event.description || 'Aktuelle Werke der Vereinsmitglieder in einer gemeinsamen Schau.'
      const kontaktBlock = variant === 'neutral'
        ? ['Kontakt für Rückfragen und Bildmaterial: über den Verein.', ``]
        : [
            verein.email ? `E-Mail:  ${verein.email}` : '', (verein as any).phone ? `Telefon: ${(verein as any).phone}` : '',
            adresse ? `Adresse: ${adresse}` : '', ``,
            verein.website || '', ``
          ]
      return {
        title: `PRESSEAUSSENDUNG – ${event.title} | ${gName}`,
        content: [
          `PRESSEAUSSENDUNG`, `Zur sofortigen Veröffentlichung`, ``,
          `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`,
          `${event.title.toUpperCase()}`, `${evType} · ${gName}`,
          `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`, ``,
          `TERMIN:   ${evDate}`, `ORT:      ${ort || adresse}`, ``,
          `───────────────────────────────────────`, `ZUR AUSSTELLUNG`, `───────────────────────────────────────`, ``,
          desc, ``,
          `${kuenstlerListe} zeigen aktuelle Werke – ein Querschnitt durch das Schaffen des Vereins.`, ``,
          STORY_1B_PRODUKT_PRESSE, ``,
          `───────────────────────────────────────`, `HINWEIS`, `───────────────────────────────────────`, ``,
          HINWEIS_LINK_QR_VORAB_SIE, ``,
          `───────────────────────────────────────`, `KONTAKT & BILDMATERIAL`, `───────────────────────────────────────`, ``,
          ...kontaktBlock,
          `– Ende der Presseaussendung –`,
        ].filter(l => l !== null && l !== undefined).join('\n')
      }
    }

    const ort = event.location || getProminenteAdresseFormatiert(galleryData, martinaData, georgData) || ''
    const isGalerieeroeffnung = event.type === 'galerieeröffnung'
    const desc = isGalerieeroeffnung ? EROEFFNUNG_LOUNGE_TEXT : (event.description || 'Malerei, Keramik und Skulptur in einem außergewöhnlichen Galerieraum.')
    const mName = martinaData?.name || 'Martina Kreinecker'
    const pName = georgData?.name || 'Georg Kreinecker'
    const mBio = martinaData?.bio || 'Malerei und Grafik – großformatige Arbeiten zwischen Abstraktion und Figuration.'
    const pBio = georgData?.bio || 'Keramik und Skulptur – handgeformte Objekte mit starker plastischer Präsenz.'
    const gName = galleryData.name || 'K2 Galerie'
    const adresse = getProminenteAdresseFormatiert(galleryData, martinaData, georgData)

    const kuenstlerBlock = variant === 'lokal' ? [
      `Die ${gName} präsentiert mit dieser ${evType} eine Zusammenschau`,
      `zweier künstlerischer Positionen, die in Dialog miteinander treten.`,
      `${mName} und ${pName} schaffen Werke, die sich gegenseitig`,
      `spiegeln und bereichern – zwischen Fläche und Raum, zwischen`,
      `malerischer Setzung und plastischer Form.`,
      ``,
      `───────────────────────────────────────`,
      `DIE KÜNSTLER:INNEN`,
      `───────────────────────────────────────`,
      ``,
      `${mName.toUpperCase()}`,
      mBio,
      ``,
      `${pName.toUpperCase()}`,
      pBio,
      ``,
    ] : []

    const kontaktBlockK2 = variant === 'neutral'
      ? [
          `Kontakt für Rückfragen und Bildmaterial: über die Galerie.`,
          ``,
          galleryData.website || galleryData.internetadresse ? `${galleryData.website || galleryData.internetadresse}` : '',
          ``,
        ]
      : [
          `Für Rückfragen, Interviewanfragen und Bildmaterial:`,
          ``,
          galleryData.email ? `E-Mail:  ${galleryData.email}` : '',
          galleryData.phone ? `Telefon: ${galleryData.phone}` : '',
          adresse ? `Adresse: ${adresse}` : '',
          galleryData.openingHours ? `Öffnungszeiten: ${galleryData.openingHours}` : '',
          ``,
          `www.k2-galerie.at`,
          ``,
        ]

    const storyBlock = variant === 'lokal' && !tenant.isOeffentlich
      ? [STORY_1A_HUMAN_PRESSE, ``, STORY_1B_PRODUKT_PRESSE, ``]
      : [STORY_1B_PRODUKT_PRESSE, ``]

    // Bei Galerieeröffnung neutral: Lead aus Muster (docs/MOK2-MUSTER-PRO-WERBETYP-EROEFFNUNG.md §5)
    const eroeffnungLead =
      isGalerieeroeffnung && variant === 'neutral'
        ? `Die ${gName} ${EROEFFNUNG_PRESSE_LEAD_PREFIX} ${evDate} mit einer Ausstellung von ${mName} und ${pName}. Zur Eröffnung lädt das Galerie-Team in die Räume ein und gibt in einer gemeinsamen Lounge Einblick in die K2-Plattform für Künstler:innen, Galerien und Kunstvereine (K2 · ök2 · VK2).`
        : null

    return {
      title: `PRESSEAUSSENDUNG – ${event.title} | ${gName}`,
      content: [
        `PRESSEAUSSENDUNG`,
        `Zur sofortigen Veröffentlichung`,
        ``,
        `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`,
        `${event.title.toUpperCase()}`,
        `${evType} · ${gName}`,
        `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`,
        ``,
        `TERMIN:   ${evDate}`,
        `ORT:      ${ort || adresse}`,
        ``,
        `───────────────────────────────────────`,
        `ZUR AUSSTELLUNG`,
        `───────────────────────────────────────`,
        ``,
        ...(eroeffnungLead ? [eroeffnungLead, ``, STORY_1B_PRODUKT_PRESSE, ``] : [desc, ``, ...storyBlock]),
        ...kuenstlerBlock,
        `───────────────────────────────────────`,
        `HINWEIS`,
        `───────────────────────────────────────`,
        ``,
        HINWEIS_LINK_QR_VORAB_SIE,
        ``,
        `───────────────────────────────────────`,
        `KONTAKT & BILDMATERIAL`,
        `───────────────────────────────────────`,
        ``,
        ...kontaktBlockK2,
        `– Ende der Presseaussendung –`,
      ].filter(l => l !== null && l !== undefined).join('\n')
    }
  }

