  // Einzelne bearbeitbare PDFs generieren
  // Leichtgewichtige Text-Export Funktionen (statt PDF) - viel weniger Memory-Belastung
  const exportPresseaussendungAsText = (presseaussendung: any, event: any) => {
    const galleryName = (() => {
      if (tenant.isVk2) return vk2Stammdaten?.verein?.name || 'Kunstverein Muster'
      const g = galleryData || {}
      return g.name || (tenant.isOeffentlich ? TENANT_CONFIGS.oeffentlich.galleryName : 'K2 Galerie')
    })()
    const g = (() => {
      if (tenant.isVk2) {
        const v = vk2Stammdaten?.verein
        return v ? { address: v.address, city: v.city, phone: (v as any).phone || '', email: v.email || '' } : {}
      }
      return galleryData || {}
    })()
    const adresseK2 = !tenant.isVk2 ? getProminenteAdresseFormatiert(galleryData, martinaData, georgData) : ''
    const galerieUrl = BASE_APP_URL + (tenant.isVk2 ? PROJECT_ROUTES.vk2.galerie : tenant.isOeffentlich ? PROJECT_ROUTES['k2-galerie'].galerieOeffentlich : PROJECT_ROUTES['k2-galerie'].galerie)

    const text = `
${'='.repeat(60)}
${galleryName.toUpperCase()}
${'='.repeat(60)}

PRESSEAUSSENDUNG

Event: ${event?.title || 'Nicht angegeben'}
Datum: ${formatEventDates(event) || 'Nicht angegeben'}

${tenant.isVk2 ? (g.address ? `Adresse: ${g.address}` : '') : (adresseK2 ? `Adresse: ${adresseK2}` : '')}
${g.phone ? `Telefon: ${g.phone}` : ''}
${g.email ? `E-Mail: ${g.email}` : ''}

${'-'.repeat(60)}

TITEL:
${presseaussendung?.title || ''}

${'-'.repeat(60)}

INHALT:
${presseaussendung?.content || ''}

${'-'.repeat(60)}
WEITERVERBREITEN: Bitte teilen Sie diese Presseinformation in Ihren Netzwerken (Facebook, Instagram, X, …). Link zur Galerie: ${galerieUrl}
Hinweis: Über Link oder QR-Code können sich Interessierte vorab ein Bild von K2, ök2 und VK2 machen – dann können wir konkrete Fragen beantworten.
${'-'.repeat(60)}

${'='.repeat(60)}
Erstellt: ${new Date().toLocaleString('de-DE')}
${'='.repeat(60)}
    `.trim()
    
    // Kopiere in Zwischenablage (sehr leichtgewichtig)
    navigator.clipboard.writeText(text).then(() => {
      alert('✅ Presseaussendung wurde in die Zwischenablage kopiert!\n\nDu kannst sie jetzt in Word, Pages oder einem Texteditor einfügen.')
    }).catch(() => {
      // Fallback: Öffne in neuem Fenster (kleiner Blob, sofort freigegeben)
      const blob = new Blob([text], { type: 'text/plain;charset=utf-8' })
      const url = URL.createObjectURL(blob)
      const win = window.open(url, '_blank')
      if (win) try { win.focus() } catch (_) { }
      setTimeout(() => URL.revokeObjectURL(url), 500)
      if (win) {
        alert('✅ Text wurde geöffnet. Du kannst ihn kopieren und in Word/Pages einfügen.')
      }
    })
  }

