                          <button type="button" onClick={() => setSettingsSubTab('lizenzbeenden')} style={{ ...innerBtn, borderColor: `${s.accent}44`, background: settingsSubTab === 'lizenzbeenden' ? `${s.accent}22` : s.bgCard }}>
                            🚪 Lizenz beenden
                          </button>
