                  setArtworkArtist('')
                  setArtworkDescription('')
                  setArtworkPrice('')
                  setArtworkPurchasePrice('')
                  setArtworkQuantity('1')
                  setSelectedFile(null)
                  setPreviewUrl(null)
                  setPhotoImageMode('freigestellt')
